/**
 * store/graphStore.ts — Central Zustand state store for FlowGraph.
 *
 * This is the single source of truth for ALL application state. Every component
 * reads from this store via hooks and mutates state through actions defined here.
 *
 * Why Zustand? It's minimal, doesn't require providers/wrappers, and its
 * selector-based subscriptions mean components only re-render when the specific
 * slice of state they care about changes.
 *
 * Architecture rule: NO direct state mutation outside of this file.
 * Components call actions; actions update state; React re-renders.
 *
 * What belongs here: all state fields and all state mutation functions.
 * What does NOT belong here: React JSX, DOM manipulation, SVG rendering.
 */

import { create } from 'zustand';
import type {
  GraphNode,
  GraphEdge,
  GraphGroup,
  GraphPhase,
  GraphMeta,
  NodeTag,
  Position,
  Transform,
  ViewMode,
  DesignTool,
  LayoutSnapshot,
  FocusSnapshot,
  OwnerFocusSnapshot,
  LaneMetrics,
  UndoSnapshot,
  CinemaSequence,
  CinemaEngagementMap,
  DiscoveryPhase,
  HeatTier,
  PathType,
  CriticalChain,
  BottleneckNode,
} from '../types/graph';
import { extractCriticalChains } from '../utils/criticalPath';
import { PHASE_PALETTE } from '../types/graph';
import { computeNormalizedEngagement, assignHeatTier } from '../utils/cinema';
import {
  computeLayout,
  computeLaneLayout,
  rebuildEdgesFromNodes,
  enforcePhaseZones,
  pushNodesOutOfPhaseBand,
  enforceAllPhaseBoundaries,
  resolveNodeOverlaps,
  computePhaseAdjustedPositions,
  NODE_W,
  NODE_H,
  GAP_Y,
  LANE_PAD_Y,
  LANE_LABEL_W,
  LEGIBILITY_PAD_X,
  LEGIBILITY_PAD_Y,
} from '../utils/layout';
import { assignOwnerColors } from '../utils/colors';
import {
  deriveGroupOwners,
  generateGroupId,
  getHiddenNodeIds,
  getAllDescendantNodeIds,
  getAllDescendantGroupIds,
  GROUP_R,
} from '../utils/grouping';

// ─── STORE INTERFACE ─────────────────────────────────────────────────────────

export interface GraphStore {
  // ── Core graph data ──────────────────────────────────────────────────────
  /** Complete list of all nodes, regardless of visibility or filtering */
  allNodes: GraphNode[];
  /** Complete list of all edges, derived from node dependencies */
  allEdges: GraphEdge[];

  // ── Visibility (filtered subset of allNodes/allEdges) ────────────────────
  /** Nodes currently rendered on canvas (subset of allNodes, filtered by activeOwners + focus mode) */
  visibleNodes: GraphNode[];
  /** Edges currently rendered on canvas (subset of allEdges, both endpoints must be visible) */
  visibleEdges: GraphEdge[];

  // ── Layout ───────────────────────────────────────────────────────────────
  /** Current x/y positions for each node by node id */
  positions: Record<string, Position>;
  /** Swim lane vertical metrics, only populated in 'lanes' view mode */
  laneMetrics: Record<string, LaneMetrics>;
  /** Which owners are currently checked (visible) in the filter sidebar */
  activeOwners: Set<string>;
  /** Color assigned to each owner, maps owner name → hex color string */
  ownerColors: Record<string, string>;

  // ── View ─────────────────────────────────────────────────────────────────
  /** Current layout mode: 'dag' = left-to-right dependency layout, 'lanes' = swim lanes by owner */
  viewMode: ViewMode;
  /**
   * Cached layouts per view mode. When the user switches from DAG to LANES and back,
   * their arrangement is restored exactly as they left it.
   */
  layoutCache: Record<string, LayoutSnapshot>;

  // ── Selection & interaction ───────────────────────────────────────────────
  /** ID of the node whose details are shown in the Inspector panel. Null if nothing is selected. */
  selectedNodeId: string | null;
  /** ID of the node currently being hovered. Drives the highlight/dim effect. */
  hoveredNodeId: string | null;
  /** ID of the node most recently jumped to via search. Used for the pulsing glow animation. */
  lastJumpedNodeId: string | null;
  /** ID of the target node for ancestor-path highlighting. All nodes/edges on any path from a root to this node are highlighted; others are ghosted. */
  pathHighlightNodeId: string | null;
  /** Which direction(s) to highlight from the target node. */
  pathHighlightMode: 'ancestors' | 'descendants' | 'both' | null;

  // ── Focus mode ───────────────────────────────────────────────────────────
  /** True when focus mode is active (user double-clicked a node in view mode) */
  focusMode: boolean;
  /** The anchor node id in focus mode (the node that was double-clicked) */
  focusNodeId: string | null;
  /** How far to traverse from the focused node: 'neighbors' = 1 hop, 'full' = all ancestors + descendants */
  focusDepth: 'neighbors' | 'full';
  /**
   * Snapshot of the graph state captured immediately before entering focus mode.
   * Used to restore the exact pre-focus layout when the user exits.
   */
  preFocusSnapshot: FocusSnapshot | null;

  // ── Canvas viewport ───────────────────────────────────────────────────────
  /** Current pan (x, y) and zoom (k) applied to the graph canvas */
  transform: Transform;
  /**
   * When non-null, Canvas.tsx will animate the transform from its current value
   * to this target using a smooth easeOutCubic "fly-to" animation.
   * Set via flyTo(); cleared by Canvas after animation completes.
   */
  flyTarget: Transform | null;

  // ── Design mode ───────────────────────────────────────────────────────────
  /** True when design mode is active (the user clicked the Design button) */
  designMode: boolean;
  /** Which design tool is currently selected */
  designTool: DesignTool;
  /** ID of the node that was first-clicked in 'connect' tool mode (the source of the new edge) */
  connectSourceId: string | null;
  /** True when there are unsaved changes since the last load/save */
  designDirty: boolean;
  undoStack: UndoSnapshot[];
  redoStack: UndoSnapshot[];
  undo: () => void;
  redo: () => void;

  // ── Groups ────────────────────────────────────────────────────────────────
  /** All groups in the graph */
  groups: GraphGroup[];
  /** IDs of nodes/groups currently selected for group creation (design mode multi-select) */
  multiSelectIds: string[];
  /** True when marquee (rubber-band) selection mode is active */
  marqueeMode: boolean;
  /** True when pan/hand tool mode is active (persistent, button-toggled) */
  panMode: boolean;
  /** ID of the selected group (shown in Inspector). Null when nothing selected. */
  selectedGroupId: string | null;

  // ── Phases ────────────────────────────────────────────────────────────────
  /** All phases in the graph (vertical time bands on the canvas) */
  phases: GraphPhase[];
  /** ID of the phase whose details are shown in the Inspector. Null if nothing selected. */
  selectedPhaseId: string | null;
  /** ID of the phase currently spotlit via the Phase Navigator. Null = show all. */
  focusedPhaseId: string | null;
  /** IDs of phases currently collapsed to a narrow strip (transient — not serialized) */
  collapsedPhaseIds: string[];

  // ── Owner Focus Mode ──────────────────────────────────────────────────────
  /** Owner lane currently spotlit. Null = no focus. */
  focusedOwner: string | null;
  /** Snapshot of state captured before entering owner focus — restored on exit. */
  preLaneFocusSnapshot: OwnerFocusSnapshot | null;
  /** Node IDs fading out after their owner was toggled off — still rendered during exit animation */
  fadingOutNodeIds: string[];
  /** Pre-toggle positions for fading-out nodes so they stay in place during the exit animation */
  fadingOutPositions: Record<string, Position>;
  /** Node IDs fading in after their owner was toggled on */
  fadingInNodeIds: string[];
  /** When true, node and edge entrance animations are skipped for the next mount cycle */
  suppressEntranceAnimation: boolean;

  /** Name of the currently-loaded JSON file, or null if no file is loaded */
  currentFileName: string | null;
  /**
   * File System Access API handle for the currently-open file.
   * When present, Save writes directly back to the file on disk (Chrome/Edge).
   * When null, Save falls back to downloading a copy.
   */
  fileHandle: FileSystemFileHandle | null;

  // ── Actions ───────────────────────────────────────────────────────────────
  /** clearGraph — resets all graph data and enters design mode for a fresh start */
  clearGraph: () => void;
  setFileHandle: (handle: FileSystemFileHandle | null) => void;
  setCurrentFileName: (name: string | null) => void;
  loadData: (nodes: GraphNode[], savedLayout?: {
    currentView?: string;
    dag?:   { positions: Record<string, Position>; transform: Transform } | null;
    lanes?: { positions: Record<string, Position>; transform: Transform } | null;
    /** @deprecated single-view format from older saves — still accepted for backward compat */
    positions?: Record<string, Position>;
    transform?: Transform;
    viewMode?: string;
  } | null, fileName?: string | null) => void;
  addNode: (node: GraphNode, clickPosition: Position) => void;
  updateNode: (id: string, changes: Partial<Omit<GraphNode, 'id'>>) => void;
  deleteNode: (id: string) => void;
  addEdge: (fromId: string, toId: string) => void;
  deleteEdge: (fromId: string, toId: string) => void;
  setTransform: (transform: Transform) => void;
  setDesignMode: (on: boolean) => void;
  setDesignTool: (tool: DesignTool) => void;
  setConnectSource: (nodeId: string | null) => void;
  setViewMode: (mode: ViewMode) => void;
  setSelectedNode: (id: string | null) => void;
  setHoveredNode: (id: string | null) => void;
  setLastJumpedNode: (id: string | null) => void;
  setPathHighlight: (id: string | null, mode?: 'ancestors' | 'descendants' | 'both') => void;
  toggleOwner: (owner: string) => void;
  toggleAllOwners: () => void;
  rebuildGraph: (animated?: boolean) => void;
  enterFocusMode: (nodeId: string) => void;
  exitFocusMode: () => void;
  setFocusDepth: (depth: 'neighbors' | 'full') => void;
  saveLayoutToCache: () => void;
  saveNamedLayout: (name: string) => void;
  loadNamedLayout: (snapshot: LayoutSnapshot, viewMode: ViewMode) => void;
  fitToScreen: (animate?: boolean) => void;
  /** Trigger a smooth animated pan+zoom to the given transform. */
  flyTo: (target: Transform) => void;
  /** Clear flyTarget after animation finishes (called by Canvas). */
  clearFlyTarget: () => void;

  // ── Group actions ──────────────────────────────────────────────────────────
  /** Create a new group from selected node IDs and optional child group IDs */
  createGroup: (
    childNodeIds: string[],
    childGroupIds: string[],
    data: { name: string; description: string }
  ) => void;
  /** Update one or more fields of an existing group */
  updateGroup: (id: string, changes: Partial<Omit<GraphGroup, 'id'>>) => void;
  /**
   * Delete a group.
   * If dissolve=true, its children remain as standalone nodes/groups.
   * If dissolve=false (default), children are also deleted.
   */
  deleteGroup: (id: string, dissolve?: boolean) => void;
  /** Toggle the collapsed/expanded state of a group */
  toggleGroupCollapse: (id: string) => void;
  /** Set the selected group ID (Inspector) */
  setSelectedGroup: (id: string | null) => void;
  /** Add or remove an item from the multi-select set (design mode) */
  toggleMultiSelect: (id: string) => void;
  /** Clear all multi-selected items */
  clearMultiSelect: () => void;
  /** Replace the entire multi-select set (used by marquee selection) */
  setMultiSelectIds: (ids: string[]) => void;
  /** Toggle the marquee (rubber-band) selection mode on/off */
  toggleMarqueeMode: () => void;
  /** Toggle the pan/hand tool mode on/off */
  togglePanMode: () => void;

  // ── Phase actions ──────────────────────────────────────────────────────────
  /** Create a new phase, optionally pre-assigning nodes and/or collapsed groups */
  createPhase: (nodeIds: string[], data: { name: string; description: string; color?: string }, groupIds?: string[]) => void;
  /** Collapse a phase band to a narrow strip */
  collapsePhase: (id: string) => void;
  /** Expand a previously collapsed phase band */
  expandPhase: (id: string) => void;
  /** Toggle the collapsed/expanded state of a phase band */
  togglePhaseCollapse: (id: string) => void;
  /** Collapse all phase bands at once */
  collapseAllPhases: () => void;
  /** Expand all phase bands at once */
  expandAllPhases: () => void;
  /** Update one or more fields of an existing phase */
  updatePhase: (id: string, changes: Partial<Omit<GraphPhase, 'id'>>) => void;
  /** Delete a phase (nodes are unaffected — they simply no longer belong to a phase) */
  deletePhase: (id: string) => void;
  /** Swap this phase one step earlier ('left') or later ('right') in the sequence */
  movePhase: (id: string, direction: 'left' | 'right') => void;
  /** Assign a set of nodes to a phase, removing them from any previous phase first */
  assignNodesToPhase: (nodeIds: string[], phaseId: string) => void;
  /** Remove a set of nodes from whichever phase they belong to */
  removeNodesFromPhase: (nodeIds: string[]) => void;
  /** Assign a set of collapsed groups to a phase, removing them from any previous phase first */
  assignGroupsToPhase: (groupIds: string[], phaseId: string) => void;
  /** Remove a set of groups from whichever phase they belong to */
  removeGroupsFromPhase: (groupIds: string[]) => void;

  // ── Clipboard ─────────────────────────────────────────────────────────────
  /** Nodes currently on the clipboard (set by copySelection) */
  clipboard: GraphNode[];
  /** Incremented each time pasteClipboard runs; Canvas uses it to suppress entrance animation */
  pasteCount: number;
  /** Incremented each time loadData runs; Canvas uses it to detect file loads for entrance animation */
  loadCount: number;
  /** Copy selected nodes to the clipboard */
  copySelection: () => void;
  /** Paste clipboard nodes as new nodes, offset by +80/+80, no edges */
  pasteClipboard: () => void;
  /** Run full phase-constraint settlement for all phases in the current view mode and write back positions */
  settleAllPhases: () => void;
  /** Re-assign phase sequence numbers by ascending mean-X of member nodes */
  reorderPhasesByPosition: () => void;
  /** Detect overlapping nodes / collapsed groups and spread them apart to remove overlaps */
  resolveOverlaps: () => void;
  /**
   * settleAndResolve — combined phase-settlement + overlap-resolution pipeline.
   *
   * Runs settleAllPhases logic to enforce phase band boundaries, then calls
   * resolveNodeOverlaps to push any remaining overlapping items apart with
   * LEGIBILITY_PAD_X/Y spacing. In LANES view, Y positions are clamped back to
   * the owner's lane bounds after resolution. Does NOT call saveLayoutToCache —
   * callers are responsible for saving to cache after this returns.
   *
   * @param anchorIds - IDs of items that must not move (e.g. the just-dragged node).
   *                    All other items push away from anchors.
   */
  settleAndResolve: (anchorIds?: Set<string>) => void;
  /** Set the selected phase ID (Inspector) */
  setSelectedPhaseId: (id: string | null) => void;
  /** Set the focused phase ID (Navigator spotlight) */
  setFocusedPhaseId: (id: string | null) => void;
  /** Enter owner focus mode for the given owner lane */
  enterOwnerFocus: (owner: string) => void;
  /** Exit owner focus mode and restore the pre-focus state */
  exitOwnerFocus: () => void;

  // ── Owner & tag management ─────────────────────────────────────────────────
  /** Override the display color for an owner */
  setOwnerColor: (owner: string, color: string) => void;
  /** Rename an owner across all nodes, updating colors and active filter set */
  renameOwner: (oldName: string, newName: string) => void;
  /** Change the color of every tag with the given label across all nodes */
  recolorTag: (label: string, color: string) => void;
  /** Rename a tag label across all nodes */
  renameTag: (oldLabel: string, newLabel: string) => void;

  // ── Tag registry ───────────────────────────────────────────────────────────
  /**
   * Session-only registry of tags created in the sidebar but not yet assigned to
   * any node. These appear in the node-edit dropdown so users can pre-define tags.
   * Not serialized — entries survive only until the next file load/clear.
   */
  tagRegistry: NodeTag[];
  /** Add a tag to the session registry (no-op if a tag with that label already exists) */
  addTagToRegistry: (tag: NodeTag) => void;
  /** Remove a tag from the session registry by label */
  removeTagFromRegistry: (label: string) => void;

  // ── Owner registry ──────────────────────────────────────────────────────────
  /**
   * Registry of owner names pre-created in the sidebar (design mode).
   * Owners here appear in the Owners filter pane and the node-edit owner dropdown
   * even before any node is assigned to them. Serialized with the file.
   */
  ownerRegistry: string[];
  /** Add an owner to the registry (no-op if the name already exists on a node or in the registry) */
  addOwnerToRegistry: (name: string) => void;
  /** Remove an owner from the registry by name (only registry-only owners; no-op if a node uses it) */
  removeOwnerFromRegistry: (name: string) => void;

  // ── File metadata ────────────────────────────────────────────────────────────
  /**
   * Metadata read from `_meta` in the loaded JSON. Preserved on save so the
   * field survives round-trips. Null for brand-new charts (defaults are injected
   * by buildExportPayload at save time).
   */
  meta: GraphMeta | null;

  // ── Cinema / Discovery ────────────────────────────────────────────────────
  /** True while the cinema overlay is displayed */
  discoveryActive: boolean;
  /**
   * Which phase of the discovery session is active.
   * null = inactive. 'cinema' = narration playing. 'transition' = end screen.
   * 'reconstruction'/'heatmap' = Phase 2/3 (not yet implemented).
   */
  discoveryPhase: DiscoveryPhase;
  /** The generated scene sequence; kept after exit for Phase 2 (Reconstruction) */
  discoverySequence: CinemaSequence | null;
  /** Index of the currently displayed scene */
  discoverySceneIndex: number;
  /** Ordered list of nodeIds that appeared in focus; Phase 2 uses these as blanks */
  discoveryVisited: string[];
  /** Raw accumulated engagement score per nodeId — integers, grows across sessions */
  discoveryEngagement: CinemaEngagementMap;
  /**
   * Normalized engagement scores — set by startHeatmap at tier-assignment time.
   * Values are ratios relative to the per-run baseline (1.0 = exactly average).
   * Empty until startHeatmap is called after a cinema run completes.
   * Phase 3 (Heatmap) reads this to assign hot/warm/cold/ice tiers.
   */
  discoveryHeatmap: CinemaEngagementMap;
  /** Per-node role during cinema: 'focus'|'lit'|'ghost'|'visited'|'danger'. Empty when cinema is inactive. */
  discoveryRoleMap: Record<string, string>;
  /** First-attempt placement result per nodeId in reconstruction mode. Only first attempt is recorded. */
  reconstructionAccuracy: Record<string, boolean>;
  /** NodeId of the label chip currently selected for placement. Null when no chip is held. */
  selectedReconstructionChip: string | null;
  /** Heat tier per nodeId after startHeatmap runs. Empty until Phase 3 starts. */
  heatTiers: Record<string, HeatTier>;

  // ── Path Types ────────────────────────────────────────────────────────────
  /** Map of edge key ("fromId:toId") → PathType. Empty = all edges are 'required' (default). */
  edgePathTypes: Record<string, PathType>;
  /** Source node ID for the Trace Path tool. Null when no trace is in progress. */
  tracePathSource: string | null;
  /** Found paths from BFS in the Trace Path tool. Each path is an ordered array of edges. */
  tracePathResults: GraphEdge[][];
  /** Index into tracePathResults for the currently highlighted path. */
  tracePathSelectedIndex: number;

  // ── Cinema actions ─────────────────────────────────────────────────────────
  /** Start the cinema with the given pre-built sequence */
  startDiscovery: (sequence: CinemaSequence) => void;
  /**
   * Called when the user clicks Finish on the last scene.
   * Atomically clears the canvas role map and sets discoveryPhase to 'transition'
   * in a single set() call — guarantees one React render, no race between
   * the roleMap clear and the phase state update.
   */
  completeDiscovery: () => void;
  /** Exit the cinema, preserving sequence and engagement for Phase 2/3 */
  exitDiscovery: () => void;
  /** Overwrite the full role map (called by CinemaOverlay on every scene change) */
  setDiscoveryRoleMap: (map: Record<string, string>) => void;
  /** Advance to the next scene */
  advanceScene: () => void;
  /** Go back to the previous scene */
  retreatScene: () => void;
  /** Record that a node appeared in focus in the current scene */
  visitNode: (nodeId: string) => void;
  /** Merge a new engagement measurement into the running totals */
  recordEngagement: (nodeId: string, score: number) => void;
  /**
   * Normalize raw engagement scores, assign heat tiers, and advance to the heatmap phase.
   * Called from two paths: completeReconstruction() (after reconstruction) and the
   * transition screen's "Skip to summary" button (direct skip). In both cases it sets
   * discoveryPhase to 'heatmap'. reconstructionAccuracy is NOT touched here — the skip
   * path leaves it as {} (never populated), which the stats strip reads as "skipped".
   */
  startHeatmap: () => void;
  /** Enter reconstruction phase — sets discoveryPhase to 'reconstruction', clears prior accuracy data */
  startReconstruction: () => void;
  /** Select or deselect a label chip by its nodeId (null deselects) */
  selectReconstructionChip: (nodeId: string | null) => void;
  /** Record first-attempt placement result; no-op if the nodeId already has a recorded result */
  recordReconstructionAttempt: (nodeId: string, correct: boolean) => void;
  /** All nodes placed — calls startHeatmap (which sets discoveryPhase to 'heatmap') then clears chip selection */
  completeReconstruction: () => void;
  /**
   * Full cinema exit from the heatmap phase. Sets discoveryActive to false and
   * discoveryPhase to null. DOM class cleanup (heatmap-*, reconstruction-*, discovery-*)
   * is handled by CinemaOverlay's useEffect cleanup when discoveryActive flips to false.
   * Preserves discoveryEngagement, discoverySequence, and reconstructionAccuracy for
   * second-visit differential cinema.
   */
  exitCinemaExperience: () => void;
  /** Update cinema author fields on a node */
  updateNodeCinemaFields: (id: string, fields: { cinemaScript?: string; cinemaBottleneck?: boolean; cinemaSkip?: boolean }) => void;
  /** Update cinema author fields on a group */
  updateGroupCinemaFields: (id: string, fields: { cinemaScript?: string; cinemaBottleneck?: boolean; cinemaSkip?: boolean }) => void;

  // ── Path Type actions ──────────────────────────────────────────────────────
  /** Set the path type for a single edge. edgeKey = "${fromId}:${toId}". Takes undo snapshot. */
  setEdgePathType: (edgeKey: string, pathType: PathType) => void;
  /** Set the same path type for multiple edges in one undo snapshot. edgeKeys = "${fromId}:${toId}[]". */
  setEdgePathTypeBatch: (edgeKeys: string[], pathType: PathType) => void;
  /** Set the source node for Trace Path mode. */
  setTracePathSource: (id: string | null) => void;
  /** Store BFS results for Trace Path mode. */
  setTracePathResults: (results: GraphEdge[][], selectedIndex?: number) => void;
  /** Advance to the next traced path (cycles). */
  nextTracePath: () => void;
  /** Go back to the previous traced path (cycles). */
  prevTracePath: () => void;
  /** Clear all Trace Path state and return to select tool. */
  clearTracePath: () => void;

  // ── Summon Mode ────────────────────────────────────────────────────────────
  /** True when summon mode is active (modal connection mode) */
  summonActive: boolean;
  /** The primary node ID from which new edges will be created (first of summonSourceIds) */
  summonSourceId: string | null;
  /** All node IDs selected as sources when summon was activated (multi-select support) */
  summonSourceIds: string[];
  /** Search filter string for the summon dock */
  summonFilter: string;
  /** Whether the connection ring visualization is shown */
  summonShowRing: boolean;
  /** SVG-space position + color for the ping animation on successful connect */
  summonPingTarget: { x: number; y: number; color: string } | null;
  /** Set of node IDs that have been connected in this summon session */
  summonConnected: Set<string>;

  activateSummon: (sourceIds: string | string[]) => void;
  deactivateSummon: () => void;
  setSummonFilter: (q: string) => void;
  toggleSummonRing: () => void;
  setSummonPingTarget: (t: { x: number; y: number; color: string } | null) => void;
  addSummonConnected: (nodeId: string) => void;

  // ── Auto Layout ────────────────────────────────────────────────────────────
  /** True while the auto-layout worker is running */
  autoLayoutRunning: boolean;
  /** Current phase name reported by the layout worker (e.g. 'assignRanks') */
  autoLayoutPhase: string;
  /**
   * Positions captured immediately before the last auto-layout run started.
   * Canvas.tsx reads this to animate nodes from their old positions to the new ones.
   * Cleared by Canvas after the transition animation completes.
   */
  autoLayoutFromPositions: Record<string, Position> | null;
  /** Trigger an auto-layout run. Pass selectedNodeIds for partial layout. */
  runAutoLayout: (selectedNodeIds?: string[]) => void;
  /** Called by Canvas after the transition animation ends to release from-positions. */
  clearAutoLayoutFromPositions: () => void;

  // ── Critical Path Explorer ────────────────────────────────────────────────
  /** True when the Critical Path Explorer panel is open */
  criticalPathActive: boolean;
  /** All critical chains extracted from edgePathTypes at activation time */
  criticalChains: CriticalChain[];
  /** Nodes that appear in two or more chains (shared bottlenecks) */
  criticalBottlenecks: BottleneckNode[];
  /** IDs of chains currently selected (highlighted on canvas) */
  criticalSelectedIds: Set<string>;
  /** True when ≥2 chains are selected for side-by-side comparison */
  criticalCompareMode: boolean;
  /** Which chain is currently being walked step-by-step. Null = browse mode. */
  criticalWalkChainId: string | null;
  /** Current step index within the walk chain (0-based) */
  criticalWalkCursor: number;

  /** Open/close the Critical Path Explorer. Opening recomputes chains from edgePathTypes. */
  toggleCriticalPath: () => void;
  /** Enter compare mode so subsequent card clicks add to the selection. */
  enterCriticalCompareMode: () => void;
  /** Exit compare mode, keeping only the first selected path. */
  exitCriticalCompareMode: () => void;
  /** Select all chains at once, enter compare mode, and fit viewport. */
  selectAllCriticalPaths: () => void;
  /** Select a chain (radio) or toggle it in/out of compare set (checkbox). */
  setCriticalSelection: (chainId: string, multi: boolean) => void;
  /** Enter step-through walk mode for the given chain. */
  enterCriticalWalk: (chainId: string) => void;
  /** Advance the walk cursor by +1 or -1 with wrap-around. */
  stepCriticalWalk: (dir: 1 | -1) => void;
  /** Exit walk mode and return to browse view. */
  exitCriticalWalk: () => void;
  /** Jump directly to a specific step in the current walk chain. */
  setCriticalWalkCursor: (index: number) => void;

  // ── Critical Path Focus Mode ──────────────────────────────────────────────
  /** True when the canvas is filtered to show only a single chain's nodes */
  criticalFocusActive: boolean;
  /** Snapshot captured before entering critical focus — restored on exit */
  preCriticalFocusSnapshot: FocusSnapshot | null;
  /** Enter focus view for the given chain: hide all non-chain nodes, fresh layout */
  enterCriticalFocus: (chainId: string) => void;
  /** Exit critical focus and restore the full graph */
  exitCriticalFocus: () => void;
}

// ─── HELPER: compute visible nodes/edges from current state ─────────────────

/**
 * deriveVisibility — filters the full node/edge list down to what should be visible
 * given the current activeOwners set and focus mode state.
 *
 * This is a pure function (no side effects) so it can be called safely from within
 * Zustand's set() callback.
 */
function deriveVisibility(
  allNodes: GraphNode[],
  allEdges: GraphEdge[],
  activeOwners: Set<string>,
  focusMode: boolean,
  focusNodeId: string | null,
  groups: GraphGroup[] = [],
  focusDepth: 'neighbors' | 'full' = 'neighbors'
): { visibleNodes: GraphNode[]; visibleEdges: GraphEdge[] } {
  // Nodes inside a collapsed group are hidden regardless of owner filter
  const hiddenByGroup = getHiddenNodeIds(groups);

  let visibleNodes: GraphNode[];

  if (focusMode && focusNodeId) {
    const focusedNode = allNodes.find((node) => node.id === focusNodeId);
    if (!focusedNode) {
      return { visibleNodes: [], visibleEdges: [] };
    }

    let focusedIds: Set<string>;

    if (focusDepth === 'full') {
      // BFS upstream (ancestors via dependencies)
      const upstream = new Set<string>([focusNodeId]);
      const upQueue = [focusNodeId];
      while (upQueue.length > 0) {
        const cur = upQueue.shift()!;
        const curNode = allNodes.find((n) => n.id === cur);
        if (curNode) {
          for (const depId of curNode.dependencies) {
            if (!upstream.has(depId)) { upstream.add(depId); upQueue.push(depId); }
          }
        }
      }
      // BFS downstream (descendants via edges)
      const downstream = new Set<string>([focusNodeId]);
      const downQueue = [focusNodeId];
      while (downQueue.length > 0) {
        const cur = downQueue.shift()!;
        for (const edge of allEdges) {
          if (edge.from === cur && !downstream.has(edge.to)) {
            downstream.add(edge.to);
            downQueue.push(edge.to);
          }
        }
      }
      focusedIds = new Set([...upstream, ...downstream]);
    } else {
      // Neighbors: 1-hop parents + children
      const directParentIds = new Set(focusedNode.dependencies);
      const directChildIds = new Set(
        allEdges.filter((edge) => edge.from === focusNodeId).map((edge) => edge.to)
      );
      focusedIds = new Set([focusNodeId, ...directParentIds, ...directChildIds]);
    }

    visibleNodes = allNodes.filter(
      (node) =>
        focusedIds.has(node.id) &&
        activeOwners.has(node.owner) &&
        !hiddenByGroup.has(node.id)
    );
  } else {
    visibleNodes = allNodes.filter(
      (node) => activeOwners.has(node.owner) && !hiddenByGroup.has(node.id)
    );
  }

  const visibleIdSet = new Set(visibleNodes.map((node) => node.id));
  const visibleEdges = allEdges.filter(
    (edge) => visibleIdSet.has(edge.from) && visibleIdSet.has(edge.to)
  );

  return { visibleNodes, visibleEdges };
}

// ─── HELPER: compute layout positions ───────────────────────────────────────

/**
 * derivePositions — computes layout positions for the given nodes and edges.
 * Returns both the positions map and (for lane mode) the lane metrics.
 *
 * When phases and groups are provided in DAG mode, they are forwarded into
 * computeLayout so the phase-stratified layering and group-cohesion sort apply.
 * enforcePhaseZones still runs afterward as a safety net for any unphased nodes
 * that topological layering may have placed inside a phase band.
 */
function derivePositions(
  visibleNodes: GraphNode[],
  visibleEdges: GraphEdge[],
  viewMode: ViewMode,
  activeOwners: Set<string>,
  allNodes: GraphNode[],
  phases?: GraphPhase[],
  groups?: GraphGroup[]
): { positions: Record<string, Position>; laneMetrics: Record<string, LaneMetrics> } {
  if (viewMode === 'lanes') {
    const { positions: rawPositions, laneMetrics } = computeLaneLayout(visibleNodes, visibleEdges, activeOwners, allNodes, phases);
    const positions = phases && phases.length > 0
      ? enforcePhaseZones(rawPositions, phases, NODE_W)
      : rawPositions;
    return { positions, laneMetrics };
  } else {
    const raw = computeLayout(visibleNodes, visibleEdges, phases, groups);
    const positions = phases && phases.length > 0
      ? enforcePhaseZones(raw, phases, NODE_W)
      : raw;
    return { positions, laneMetrics: {} };
  }
}

// ─── AUTO-LAYOUT WORKER (module-level singleton) ────────────────────────────
// Kept outside the store so we can terminate/recreate it without triggering renders.
let autoLayoutWorker: Worker | null = null;

// ─── STORE ──────────────────────────────────────────────────────────────────

export const useGraphStore = create<GraphStore>((set, get) => ({
  // ── Initial state ─────────────────────────────────────────────────────────
  allNodes: [],
  allEdges: [],
  visibleNodes: [],
  visibleEdges: [],
  positions: {},
  laneMetrics: {},
  activeOwners: new Set(),
  ownerColors: {},
  viewMode: 'dag',
  layoutCache: {},
  selectedNodeId: null,
  hoveredNodeId: null,
  lastJumpedNodeId: null,
  pathHighlightNodeId: null,
  pathHighlightMode: null,
  focusMode: false,
  focusNodeId: null,
  focusDepth: 'neighbors',
  preFocusSnapshot: null,
  transform: { x: 0, y: 0, k: 1 },
  flyTarget: null,
  designMode: false,
  designTool: 'select',
  connectSourceId: null,
  designDirty: false,
  undoStack: [],
  redoStack: [],
  groups: [],
  multiSelectIds: [],
  marqueeMode: false,
  panMode: false,
  selectedGroupId: null,
  phases: [],
  selectedPhaseId: null,
  focusedPhaseId: null,
  collapsedPhaseIds: [],
  focusedOwner: null,
  preLaneFocusSnapshot: null,
  fadingOutNodeIds: [],
  fadingOutPositions: {},
  fadingInNodeIds: [],
  suppressEntranceAnimation: false,
  currentFileName: null,
  fileHandle: null,
  clipboard: [],
  pasteCount: 0,
  loadCount: 0,
  tagRegistry: [],
  ownerRegistry: [],
  meta: null,
  discoveryActive: false,
  discoveryPhase: null,
  discoverySequence: null,
  discoverySceneIndex: 0,
  discoveryVisited: [],
  discoveryEngagement: {},
  discoveryHeatmap: {},
  discoveryRoleMap: {},
  reconstructionAccuracy: {},
  selectedReconstructionChip: null,
  heatTiers: {},
  edgePathTypes: {},
  tracePathSource: null,
  tracePathResults: [],
  tracePathSelectedIndex: 0,
  summonActive: false,
  summonSourceId: null,
  summonSourceIds: [],
  summonFilter: '',
  summonShowRing: false,
  summonPingTarget: null,
  summonConnected: new Set(),
  autoLayoutRunning: false,
  autoLayoutPhase: '',
  autoLayoutFromPositions: null,
  criticalPathActive: false,
  criticalChains: [],
  criticalBottlenecks: [],
  criticalSelectedIds: new Set(),
  criticalCompareMode: false,
  criticalWalkChainId: null,
  criticalWalkCursor: 0,
  criticalFocusActive: false,
  preCriticalFocusSnapshot: null,

  // ── clearGraph ────────────────────────────────────────────────────────────
  clearGraph: () => {
    set({
      allNodes: [],
      allEdges: [],
      visibleNodes: [],
      visibleEdges: [],
      positions: {},
      laneMetrics: {},
      activeOwners: new Set(),
      ownerColors: {},
      viewMode: 'dag',
      layoutCache: {},
      selectedNodeId: null,
      hoveredNodeId: null,
      lastJumpedNodeId: null,
      pathHighlightNodeId: null,
      pathHighlightMode: null,
      focusMode: false,
      focusNodeId: null,
      focusDepth: 'neighbors',
      preFocusSnapshot: null,
      transform: { x: 0, y: 0, k: 1 },
      designMode: true,
      designTool: 'select',
      connectSourceId: null,
      designDirty: false,
      undoStack: [],
      redoStack: [],
      groups: [],
      multiSelectIds: [],
      marqueeMode: false,
      selectedGroupId: null,
      phases: [],
      selectedPhaseId: null,
      focusedPhaseId: null,
      collapsedPhaseIds: [],
      focusedOwner: null,
      preLaneFocusSnapshot: null,
      currentFileName: null,
      fileHandle: null,
      tagRegistry: [],
      ownerRegistry: [],
      meta: null,
      discoveryActive: false,
      discoveryPhase: null,
      discoverySequence: null,
      discoverySceneIndex: 0,
      discoveryVisited: [],
      discoveryEngagement: {},
      discoveryHeatmap: {},
      discoveryRoleMap: {},
      reconstructionAccuracy: {},
      selectedReconstructionChip: null,
      heatTiers: {},
      edgePathTypes: {},
      tracePathSource: null,
      tracePathResults: [],
      tracePathSelectedIndex: 0,
      summonActive: false,
      summonSourceId: null,
      summonSourceIds: [],
      summonFilter: '',
      summonShowRing: false,
      summonPingTarget: null,
      summonConnected: new Set(),
      autoLayoutRunning: false,
      autoLayoutPhase: '',
      autoLayoutFromPositions: null,
      loadCount: 0,
      criticalPathActive: false,
      criticalChains: [],
      criticalBottlenecks: [],
      criticalSelectedIds: new Set(),
      criticalCompareMode: false,
      criticalWalkChainId: null,
      criticalWalkCursor: 0,
      criticalFocusActive: false,
      preCriticalFocusSnapshot: null,
    });
  },

  // ── setFileHandle ─────────────────────────────────────────────────────────
  setFileHandle: (handle) => set({ fileHandle: handle }),
  setCurrentFileName: (name) => set({ currentFileName: name }),

  // ── loadData ─────────────────────────────────────────────────────────────

  /**
   * loadData — ingests a new node array, rebuilds all derived state, and renders.
   *
   * Called when the user loads a JSON file. Resets all state (layout cache,
   * focus mode, design mode, etc.) and computes a fresh layout.
   */
  loadData: (nodes, savedLayout, fileName) => {
    const rawEdges = rebuildEdgesFromNodes(nodes);
    const allEdges = rawEdges;
    const owners = [...new Set(nodes.map((node) => node.owner))];
    const ownerColors = assignOwnerColors(owners);
    const activeOwners = new Set(owners);

    // Extract groups from savedLayout if present
    const groups: GraphGroup[] = (savedLayout as { groups?: GraphGroup[] } | null)?.groups ?? [];
    // Extract phases from savedLayout if present (backward compat — default empty)
    const phases: GraphPhase[] = (savedLayout as { phases?: GraphPhase[] } | null)?.phases ?? [];
    // Extract tagRegistry from savedLayout if present (backward compat — default empty)
    const tagRegistry: NodeTag[] = (savedLayout as { tagRegistry?: NodeTag[] } | null)?.tagRegistry ?? [];
    // Extract ownerRegistry from savedLayout if present (backward compat — default empty)
    const ownerRegistry: string[] = (savedLayout as { ownerRegistry?: string[] } | null)?.ownerRegistry ?? [];
    // Extract _meta if present — preserved as-is so it round-trips through saves
    const meta: GraphMeta | null = (savedLayout as { meta?: GraphMeta } | null)?.meta ?? null;
    // Extract edgePathTypes — parallel map for per-edge path type assignments
    const rawEdgePathTypes: Record<string, string> =
      (savedLayout as { edgePathTypes?: Record<string, string> } | null)?.edgePathTypes ?? {};
    // Remap legacy PathType values from old saved files
    const LEGACY_REMAP: Record<string, PathType> = { required: 'standard', alternative: 'optional' };
    const edgePathTypes: Record<string, PathType> = {};
    for (const [key, val] of Object.entries(rawEdgePathTypes)) {
      edgePathTypes[key] = (LEGACY_REMAP[val] ?? val) as PathType;
    }

    // Inject runtime pathType into allEdges from the loaded map
    if (Object.keys(edgePathTypes).length > 0) {
      for (const edge of allEdges) {
        const pt = edgePathTypes[`${edge.from}:${edge.to}`];
        if (pt) edge.pathType = pt;
      }
    }

    const { visibleNodes, visibleEdges } = deriveVisibility(
      nodes, allEdges, activeOwners, false, null, groups
    );

    // ── Normalise savedLayout into the new two-view format ────────────────
    // Old format: { positions, transform, viewMode }
    // New format: { currentView, dag, lanes }
    let restoredViewMode: ViewMode = 'dag';
    let activeLayout: { positions: Record<string, Position>; transform: Transform } | null = null;
    const restoredCache: Record<string, { positions: Record<string, Position>; transform: Transform }> = {};

    if (savedLayout) {
      if (savedLayout.dag || savedLayout.lanes) {
        // New two-view format
        restoredViewMode = savedLayout.currentView === 'lanes' ? 'lanes' : 'dag';
        if (savedLayout.dag)   restoredCache['dag']   = savedLayout.dag;
        if (savedLayout.lanes) restoredCache['lanes'] = savedLayout.lanes;
        activeLayout = restoredCache[restoredViewMode] ?? null;
      } else if (savedLayout.positions && savedLayout.transform) {
        // Old single-view format (backward compat)
        restoredViewMode = savedLayout.viewMode === 'lanes' ? 'lanes' : 'dag';
        activeLayout = { positions: savedLayout.positions, transform: savedLayout.transform };
        restoredCache[restoredViewMode] = activeLayout;
      }
    }

    // A saved layout is only usable when it actually contains positions.
    // If the active view's positions are empty (e.g. file saved while in Lanes view so
    // dag.positions = {}), fall back to a fresh layout rather than rendering all nodes
    // stacked at the origin.
    const hasValidSavedPositions =
      activeLayout != null && Object.keys(activeLayout.positions).length > 0;

    // Compute fresh layout for the active view (used as fallback for missing positions)
    const { positions: freshPositions, laneMetrics } = hasValidSavedPositions
      ? derivePositions(visibleNodes, visibleEdges, restoredViewMode, activeOwners, nodes)
      : derivePositions(visibleNodes, visibleEdges, 'dag', activeOwners, nodes, phases);

    const rawActivePositions = hasValidSavedPositions ? activeLayout!.positions : freshPositions;
    const activePositions = restoredViewMode === 'lanes' && phases.length > 0
      ? enforceAllPhaseBoundaries(rawActivePositions, phases, groups, GROUP_R, LANE_LABEL_W)
      : rawActivePositions;

    set({
      allNodes: nodes,
      allEdges,
      visibleNodes,
      visibleEdges,
      positions: activePositions,
      laneMetrics,
      activeOwners,
      ownerColors,
      viewMode: activeLayout ? restoredViewMode : 'dag',
      // Pre-populate the cache so switching views restores the saved arrangement
      layoutCache: restoredCache,
      selectedNodeId: null,
      hoveredNodeId: null,
      lastJumpedNodeId: null,
      pathHighlightNodeId: null,
      pathHighlightMode: null,
      focusMode: false,
      focusNodeId: null,
      focusDepth: 'neighbors',
      preFocusSnapshot: null,
      designMode: false,
      designTool: 'select',
      connectSourceId: null,
      designDirty: false,
      undoStack: [],
      redoStack: [],
      groups,
      multiSelectIds: [],
      marqueeMode: false,
      selectedGroupId: null,
      phases,
      selectedPhaseId: null,
      focusedPhaseId: null,
      collapsedPhaseIds: [],
      focusedOwner: null,
      preLaneFocusSnapshot: null,
      tagRegistry,
      ownerRegistry,
      meta,
      transform: hasValidSavedPositions ? activeLayout!.transform : { x: 0, y: 0, k: 1 },
      currentFileName: fileName ?? null,
      fileHandle: null, // caller sets this via setFileHandle after loadData
      // Extract persisted engagement scores — stored under _layout.discoveryEngagement
      discoveryEngagement: (savedLayout as { discoveryEngagement?: CinemaEngagementMap } | null)?.discoveryEngagement ?? {},
      // Reset transient cinema state on every file load
      discoveryActive: false,
      discoveryPhase: null,
      discoverySequence: null,
      discoverySceneIndex: 0,
      discoveryVisited: [],
      discoveryHeatmap: {},
      reconstructionAccuracy: {},
      selectedReconstructionChip: null,
      heatTiers: {},
      edgePathTypes,
      tracePathSource: null,
      tracePathResults: [],
      tracePathSelectedIndex: 0,
      loadCount: get().loadCount + 1,
      criticalPathActive: false,
      criticalChains: [],
      criticalBottlenecks: [],
      criticalSelectedIds: new Set(),
      criticalCompareMode: false,
      criticalWalkChainId: null,
      criticalWalkCursor: 0,
      criticalFocusActive: false,
      preCriticalFocusSnapshot: null,
    });
  },

  // ── addNode ───────────────────────────────────────────────────────────────

  /**
   * addNode — adds a new node to the graph and places it at the given canvas position.
   *
   * The new node is appended to allNodes, edges are rebuilt, and the canvas
   * re-renders with the node at the click position. Does NOT recompute the full layout
   * (so existing nodes don't jump around when a new one is added).
   */
  addNode: (newNode: GraphNode, clickPosition: Position) => {
    const state = get();

    // Prevent duplicate IDs
    if (state.allNodes.find((node) => node.id === newNode.id)) {
      console.warn(`addNode: node with id "${newNode.id}" already exists. Skipping.`);
      return;
    }

    const undoSnapshot: UndoSnapshot = { nodes: [...state.allNodes], positions: { ...state.positions }, groups: [...state.groups], laneMetrics: { ...state.laneMetrics } };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);

    const allNodes = [...state.allNodes, newNode];
    const allEdges = rebuildEdgesFromNodes(allNodes);

    // Assign color if this is a new owner
    const ownerColors = assignOwnerColors(
      [...new Set(allNodes.map((node) => node.owner))],
      state.ownerColors
    );

    // Make sure the new owner is active (visible)
    const activeOwners = new Set([...state.activeOwners, newNode.owner]);

    const { visibleNodes, visibleEdges } = deriveVisibility(
      allNodes, allEdges, activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    // Place the new node centered on the click position
    const newPositions = {
      ...state.positions,
      [newNode.id]: {
        x: clickPosition.x - NODE_W / 2,
        y: clickPosition.y - NODE_H / 2,
      },
    };

    set({
      allNodes,
      allEdges,
      visibleNodes,
      visibleEdges,
      positions: newPositions,
      ownerColors,
      activeOwners,
      designDirty: true,
      undoStack,
      redoStack: [],
    });
    // Resolve overlaps so the new node never lands on top of an existing one.
    // The new node itself is the anchor — surrounding nodes push away from it.
    get().settleAndResolve(new Set([newNode.id]));
  },

  // ── updateNode ────────────────────────────────────────────────────────────

  /**
   * updateNode — updates one or more fields of an existing node.
   *
   * If the owner changes and it's a new owner, assigns a color for it.
   * Does not recompute layout (node stays in its current position).
   */
  updateNode: (id: string, changes: Partial<Omit<GraphNode, 'id'>>) => {
    const state = get();

    const undoSnapshot: UndoSnapshot = { nodes: [...state.allNodes], positions: { ...state.positions }, groups: [...state.groups], laneMetrics: { ...state.laneMetrics } };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);

    const allNodes = state.allNodes.map((node) =>
      node.id === id ? { ...node, ...changes } : node
    );

    const ownerColors = assignOwnerColors(
      [...new Set(allNodes.map((node) => node.owner))],
      state.ownerColors
    );

    const ownerChanged = changes.owner !== undefined &&
      changes.owner !== state.allNodes.find((n) => n.id === id)?.owner;

    // Compute activeOwners based on current filter context.
    let activeOwners: Set<string>;
    if (ownerChanged && state.focusedOwner) {
      // Owner Focus Mode: re-derive the connected-owners set so the focused
      // owner's upstream/downstream lanes stay correct after the node's owner changes.
      const fo = state.focusedOwner;
      const foNodeIds = new Set(allNodes.filter((n) => n.owner === fo).map((n) => n.id));
      const connected = new Set([fo]);
      allNodes.forEach((n) => {
        if (n.owner === fo) {
          n.dependencies.forEach((dep) => {
            const d = allNodes.find((x) => x.id === dep);
            if (d && d.owner !== fo) connected.add(d.owner);
          });
        }
        if (n.owner !== fo && n.dependencies.some((dep) => foNodeIds.has(dep))) {
          connected.add(n.owner);
        }
      });
      activeOwners = connected;
    } else if (ownerChanged && changes.owner) {
      // Regular filter: auto-show the new owner only if it is brand new
      // (not in ownerRegistry and not used by any other node). If it's a
      // known owner that was deliberately filtered out, respect the filter.
      const isNewOwner =
        !state.ownerRegistry.includes(changes.owner) &&
        !state.allNodes.some((n) => n.id !== id && n.owner === changes.owner);
      activeOwners = new Set(state.activeOwners);
      if (isNewOwner) activeOwners.add(changes.owner);
    } else {
      activeOwners = new Set(state.activeOwners);
    }

    const { visibleNodes, visibleEdges } = deriveVisibility(
      allNodes, state.allEdges, activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    if (ownerChanged && state.focusedOwner) {
      // Full position reflow — same as re-entering owner focus with updated graph.
      const { positions, laneMetrics } = derivePositions(
        visibleNodes, visibleEdges, state.viewMode, activeOwners, allNodes
      );
      set({ allNodes, visibleNodes, visibleEdges, ownerColors, activeOwners, positions, laneMetrics, designDirty: true, undoStack, redoStack: [] });
    } else if (ownerChanged && state.viewMode === 'lanes') {
      // Lanes view without owner focus: snap the node into its new lane and
      // translate all other nodes by the lane-Y delta (same pattern as toggleOwner).
      const { positions: freshPositions, laneMetrics } =
        computeLaneLayout(visibleNodes, visibleEdges, activeOwners, allNodes, state.phases.length > 0 ? state.phases : undefined);

      const positions: Record<string, Position> = { ...state.positions };

      // Translate existing nodes by their lane's Y delta
      visibleNodes.forEach((n) => {
        if (n.id === id) return; // handled below
        const oldLane = state.laneMetrics[n.owner];
        const newLane = laneMetrics[n.owner];
        if (oldLane && newLane && state.positions[n.id]) {
          positions[n.id] = {
            x: state.positions[n.id].x,
            y: state.positions[n.id].y + (newLane.y - oldLane.y),
          };
        }
      });

      // Place the changed node in its new lane without overlapping existing nodes.
      // Use the fresh layout's X (column based on dependency depth), and find Y
      // by looking only at occupants in the same column — so nodes in other columns
      // don't push the new node unnecessarily far down.
      if (freshPositions[id]) {
        const newOwner = changes.owner as string;
        const targetLane = laneMetrics[newOwner];
        const laneTop = (targetLane?.y ?? 0) + LANE_PAD_Y;
        const targetX = freshPositions[id].x;
        const laneOccupants = visibleNodes.filter((n) => n.id !== id && n.owner === newOwner);
        // Nodes sharing the same column (within half a node width).
        const colOccupants = laneOccupants.filter(
          (n) => Math.abs((positions[n.id]?.x ?? 0) - targetX) < NODE_W * 0.5
        );
        if (colOccupants.length === 0) {
          // Column is clear — anchor to lane top.
          positions[id] = { x: targetX, y: laneTop };
        } else {
          const maxColY = Math.max(...colOccupants.map((n) => positions[n.id]?.y ?? laneTop));
          positions[id] = { x: targetX, y: maxColY + NODE_H + GAP_Y };
        }
      }

      set({ allNodes, visibleNodes, visibleEdges, ownerColors, activeOwners, positions, laneMetrics, designDirty: true, undoStack, redoStack: [] });
    } else {
      set({ allNodes, visibleNodes, visibleEdges, ownerColors, activeOwners, designDirty: true, undoStack, redoStack: [] });
    }
  },

  // ── deleteNode ────────────────────────────────────────────────────────────

  /**
   * deleteNode — removes a node and all edges connected to it.
   *
   * Also removes the deleted node's id from all other nodes' dependency lists,
   * so no dangling references remain in the data.
   */
  deleteNode: (id: string) => {
    const state = get();

    const undoSnapshot: UndoSnapshot = { nodes: [...state.allNodes], positions: { ...state.positions }, groups: [...state.groups], laneMetrics: { ...state.laneMetrics } };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);

    // Remove from node list
    let allNodes = state.allNodes.filter((node) => node.id !== id);

    // Remove this node from any other node's dependencies
    allNodes = allNodes.map((node) => ({
      ...node,
      dependencies: node.dependencies.filter((depId) => depId !== id),
    }));

    const allEdges = rebuildEdgesFromNodes(allNodes);

    // Clear selection if the deleted node was selected
    const selectedNodeId = state.selectedNodeId === id ? null : state.selectedNodeId;

    // Remove position
    const positions = { ...state.positions };
    delete positions[id];

    // Remove from any group's childNodeIds
    const groups = state.groups.map((g) => ({
      ...g,
      childNodeIds: g.childNodeIds.filter((nid) => nid !== id),
    }));

    const { visibleNodes, visibleEdges } = deriveVisibility(
      allNodes, allEdges, state.activeOwners, state.focusMode, state.focusNodeId, groups
    );

    set({ allNodes, allEdges, visibleNodes, visibleEdges, positions, selectedNodeId, groups, designDirty: true, undoStack, redoStack: [] });
  },

  // ── addEdge ───────────────────────────────────────────────────────────────

  /**
   * addEdge — creates a directed connection from fromId to toId.
   *
   * "from → to" means "to depends on from" (from must happen before to).
   * Silently ignores duplicate edges and self-connections.
   */
  addEdge: (fromId: string, toId: string) => {
    const state = get();

    // Guard: no self-connections
    if (fromId === toId) return;

    // Guard: no duplicate edges
    if (state.allEdges.find((edge) => edge.from === fromId && edge.to === toId)) return;

    const undoSnapshot: UndoSnapshot = { nodes: [...state.allNodes], positions: { ...state.positions }, groups: [...state.groups], laneMetrics: { ...state.laneMetrics } };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);

    // Add fromId to toNode's dependencies array
    const allNodes = state.allNodes.map((node) => {
      if (node.id === toId && !node.dependencies.includes(fromId)) {
        return { ...node, dependencies: [...node.dependencies, fromId] };
      }
      return node;
    });

    const allEdges = rebuildEdgesFromNodes(allNodes);

    const { visibleNodes, visibleEdges } = deriveVisibility(
      allNodes, allEdges, state.activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    set({ allNodes, allEdges, visibleNodes, visibleEdges, designDirty: true, undoStack, redoStack: [] });
  },

  // ── deleteEdge ────────────────────────────────────────────────────────────

  /**
   * deleteEdge — removes the connection from fromId to toId.
   *
   * Removes fromId from toNode's dependencies array and removes the edge from allEdges.
   */
  deleteEdge: (fromId: string, toId: string) => {
    const state = get();

    const undoSnapshot: UndoSnapshot = { nodes: [...state.allNodes], positions: { ...state.positions }, groups: [...state.groups], laneMetrics: { ...state.laneMetrics } };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);

    const allNodes = state.allNodes.map((node) => {
      if (node.id === toId) {
        return { ...node, dependencies: node.dependencies.filter((depId) => depId !== fromId) };
      }
      return node;
    });

    const allEdges = rebuildEdgesFromNodes(allNodes);

    const { visibleNodes, visibleEdges } = deriveVisibility(
      allNodes, allEdges, state.activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    set({ allNodes, allEdges, visibleNodes, visibleEdges, designDirty: true, undoStack, redoStack: [] });
  },

  // ── setTransform ──────────────────────────────────────────────────────────
  setTransform: (transform: Transform) => set({ transform }),

  // ── flyTo / clearFlyTarget ────────────────────────────────────────────────
  flyTo: (target: Transform) => set({ flyTarget: target }),
  clearFlyTarget: () => set({ flyTarget: null }),

  // ── setDesignMode ─────────────────────────────────────────────────────────
  setDesignMode: (on: boolean) => {
    set({
      designMode: on,
      // Reset tool to 'select' when toggling design mode on or off
      designTool: 'select',
      connectSourceId: null,
      // Clear selection and marquee mode when exiting design mode
      ...(on ? {} : {
        selectedNodeId: null,
        selectedGroupId: null,
        selectedPhaseId: null,
        multiSelectIds: [],
        marqueeMode: false,
      }),
    });
  },

  // ── setDesignTool ─────────────────────────────────────────────────────────
  setDesignTool: (tool: DesignTool) => {
    set({
      designTool: tool,
      // Clear any in-progress connection when switching tools
      connectSourceId: tool !== 'connect' ? null : get().connectSourceId,
      // Clear trace path state when leaving tracePath mode
      ...(tool !== 'tracePath' ? { tracePathSource: null, tracePathResults: [], tracePathSelectedIndex: 0 } : {}),
      // Marquee mode only makes sense in select tool
      ...(tool !== 'select' ? { marqueeMode: false } : {}),
    });
  },

  // ── setConnectSource ──────────────────────────────────────────────────────
  setConnectSource: (nodeId: string | null) => set({ connectSourceId: nodeId }),

  // ── setViewMode ───────────────────────────────────────────────────────────

  /**
   * setViewMode — switches between DAG and LANES layout, caching the current layout first.
   *
   * If a cached layout exists for the target mode, it's restored exactly.
   * If not, a fresh layout is computed.
   */
  setViewMode: (mode: ViewMode) => {
    const state = get();
    if (mode === state.viewMode) return;

    set({ suppressEntranceAnimation: true });
    setTimeout(() => set({ suppressEntranceAnimation: false }), 100);

    // Only persist/restore the layout cache when NOT in focus mode.
    // Focus mode shows a subgraph — saving those positions would corrupt the full-graph cache,
    // and restoring a full-graph cache while in focus would cause a nodes/positions mismatch.
    const cache = { ...state.layoutCache };
    if (!state.focusMode && Object.keys(state.positions).length > 0) {
      cache[state.viewMode] = {
        positions: { ...state.positions },
        transform: { ...state.transform },
      };
    }

    const cachedLayout = !state.focusMode ? cache[mode] : null;

    if (cachedLayout) {
      // Restore the layout the user left behind, then re-enforce phase zones in case
      // phases were added/changed since the cache was saved.
      const restoredPositions = state.phases.length > 0
        ? mode === 'dag'
          ? enforcePhaseZones(cachedLayout.positions, state.phases, NODE_W)
          : enforceAllPhaseBoundaries(cachedLayout.positions, state.phases, state.groups, GROUP_R, LANE_LABEL_W)
        : cachedLayout.positions;
      // Apply positions/viewMode first (keep current transform), then fly to the saved transform.
      set({
        viewMode: mode,
        layoutCache: cache,
        positions: restoredPositions,
        laneMetrics: mode === 'lanes'
          ? computeLaneLayout(state.visibleNodes, state.visibleEdges, state.activeOwners, state.allNodes, state.phases.length > 0 ? state.phases : undefined).laneMetrics
          : {},
      });
      set({ flyTarget: cachedLayout.transform });
    } else {
      // No cache (or in focus mode) — compute fresh positions for the current visible set
      const { positions: rawPositions, laneMetrics } = derivePositions(
        state.visibleNodes, state.visibleEdges, mode, state.activeOwners, state.allNodes,
        state.phases.length > 0 ? state.phases : undefined
      );
      const positions = state.phases.length > 0
        ? enforceAllPhaseBoundaries(
            rawPositions, state.phases, state.groups, GROUP_R,
            mode === 'lanes' ? LANE_LABEL_W : 0
          )
        : rawPositions;
      set({ viewMode: mode, layoutCache: cache, positions, laneMetrics });
      setTimeout(() => get().fitToScreen(), 60);
    }
  },

  // ── setSelectedNode ───────────────────────────────────────────────────────
  setSelectedNode: (id: string | null) => set((s) => ({
    selectedNodeId: id === null && s.focusMode ? s.focusNodeId : id,
    selectedGroupId: null,
    selectedPhaseId: id !== null ? null : s.selectedPhaseId,
    lastJumpedNodeId: s.lastJumpedNodeId && s.lastJumpedNodeId !== id ? null : s.lastJumpedNodeId,
    multiSelectIds: [],
    // Clear path highlight when selection changes to a different node
    pathHighlightNodeId: s.pathHighlightNodeId === id ? s.pathHighlightNodeId : null,
    pathHighlightMode: s.pathHighlightNodeId === id ? s.pathHighlightMode : null,
  })),

  // ── setHoveredNode ────────────────────────────────────────────────────────
  setHoveredNode: (id: string | null) => set({ hoveredNodeId: id }),

  // ── setPathHighlight ──────────────────────────────────────────────────────
  setPathHighlight: (id: string | null, mode?: 'ancestors' | 'descendants' | 'both') => set({ pathHighlightNodeId: id, pathHighlightMode: mode ?? null }),

  // ── setFocusDepth ─────────────────────────────────────────────────────────
  setFocusDepth: (depth: 'neighbors' | 'full') => {
    const state = get();
    if (!state.focusMode || !state.focusNodeId) return;
    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, true, state.focusNodeId, state.groups, depth
    );
    const { positions, laneMetrics } = derivePositions(
      visibleNodes, visibleEdges, state.viewMode, state.activeOwners, state.allNodes
    );
    set({ focusDepth: depth, visibleNodes, visibleEdges, positions, laneMetrics });
    setTimeout(() => get().fitToScreen(), 60);
  },

  // ── setLastJumpedNode ─────────────────────────────────────────────────────
  setLastJumpedNode: (id: string | null) => set({ lastJumpedNodeId: id }),

  // ── undo ──────────────────────────────────────────────────────────────────
  undo: () => {
    const state = get();
    if (state.undoStack.length === 0) return;
    const prev = state.undoStack[state.undoStack.length - 1];
    const newUndoStack = state.undoStack.slice(0, -1);
    const newRedoStack = [...state.redoStack, { nodes: [...state.allNodes], positions: { ...state.positions }, groups: [...state.groups], edgePathTypes: { ...state.edgePathTypes }, laneMetrics: { ...state.laneMetrics } }];

    const allNodes = prev.nodes;
    const prevGroups = prev.groups ?? [];
    const prevEdgePathTypes = prev.edgePathTypes ?? state.edgePathTypes;
    const rawEdges = rebuildEdgesFromNodes(allNodes);
    if (Object.keys(prevEdgePathTypes).length > 0) {
      for (const edge of rawEdges) {
        const pt = prevEdgePathTypes[`${edge.from}:${edge.to}`];
        if (pt) edge.pathType = pt;
      }
    }
    const allEdges = rawEdges;
    const owners = [...new Set(allNodes.map((n) => n.owner))];
    const ownerColors = assignOwnerColors(owners, state.ownerColors);
    const activeOwners = new Set([...state.activeOwners].filter((o) => allNodes.some((n) => n.owner === o)));
    const { visibleNodes, visibleEdges } = deriveVisibility(allNodes, allEdges, activeOwners, state.focusMode, state.focusNodeId, prevGroups);

    set({
      allNodes, allEdges, visibleNodes, visibleEdges,
      positions: prev.positions, ownerColors, activeOwners, groups: prevGroups,
      edgePathTypes: prevEdgePathTypes,
      laneMetrics: prev.laneMetrics ?? state.laneMetrics,
      undoStack: newUndoStack, redoStack: newRedoStack, designDirty: true,
    });
  },

  // ── redo ──────────────────────────────────────────────────────────────────
  redo: () => {
    const state = get();
    if (state.redoStack.length === 0) return;
    const next = state.redoStack[state.redoStack.length - 1];
    const newRedoStack = state.redoStack.slice(0, -1);
    const newUndoStack = [...state.undoStack, { nodes: [...state.allNodes], positions: { ...state.positions }, groups: [...state.groups], edgePathTypes: { ...state.edgePathTypes }, laneMetrics: { ...state.laneMetrics } }];

    const allNodes = next.nodes;
    const nextGroups = next.groups ?? [];
    const nextEdgePathTypes = next.edgePathTypes ?? state.edgePathTypes;
    const rawEdges = rebuildEdgesFromNodes(allNodes);
    if (Object.keys(nextEdgePathTypes).length > 0) {
      for (const edge of rawEdges) {
        const pt = nextEdgePathTypes[`${edge.from}:${edge.to}`];
        if (pt) edge.pathType = pt;
      }
    }
    const allEdges = rawEdges;
    const owners = [...new Set(allNodes.map((n) => n.owner))];
    const ownerColors = assignOwnerColors(owners, state.ownerColors);
    const activeOwners = new Set([...state.activeOwners].filter((o) => allNodes.some((n) => n.owner === o)));
    const { visibleNodes, visibleEdges } = deriveVisibility(allNodes, allEdges, activeOwners, state.focusMode, state.focusNodeId, nextGroups);

    set({
      allNodes, allEdges, visibleNodes, visibleEdges,
      positions: next.positions, ownerColors, activeOwners, groups: nextGroups,
      edgePathTypes: nextEdgePathTypes,
      laneMetrics: next.laneMetrics ?? state.laneMetrics,
      undoStack: newUndoStack, redoStack: newRedoStack, designDirty: true,
    });
  },

  // ── toggleOwner ───────────────────────────────────────────────────────────

  /**
   * toggleOwner — shows or hides all nodes belonging to an owner in the filter sidebar.
   *
   * After updating visibility, positions are recomputed for the new visible set.
   * Existing positions are PRESERVED so the user's manual layout is not destroyed —
   * only nodes that are newly visible (no existing position) get fresh computed positions.
   */
  toggleOwner: (owner: string) => {
    const state = get();
    const activeOwners = new Set(state.activeOwners);

    if (activeOwners.has(owner)) {
      activeOwners.delete(owner);
    } else {
      activeOwners.add(owner);
    }

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    // Compute fresh layout for the new visible set, then merge:
    // nodes that already have a position keep it; only newly-visible nodes get a fresh slot.
    const { positions: freshPositions, laneMetrics } = derivePositions(
      visibleNodes, visibleEdges, state.viewMode, activeOwners, state.allNodes, state.phases, state.groups
    );
    const positions: Record<string, Position> = { ...freshPositions };

    // Always use freshPositions for all visible nodes — full reflow on every toggle
    // gives the optimal layout for the current visible set, whether hiding or revealing.

    // Clear selection if the selected node's owner was just hidden
    const selectedNodeId =
      state.selectedNodeId && !activeOwners.has(
        state.allNodes.find((n) => n.id === state.selectedNodeId)?.owner ?? ''
      )
        ? null
        : state.selectedNodeId;

    const enforcedPositions = state.phases.length > 0
      ? enforceAllPhaseBoundaries(positions, state.phases, state.groups, GROUP_R,
          state.viewMode === 'lanes' ? LANE_LABEL_W : 0)
      : positions;
    const collapsedGroupIds = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    const finalPositions = resolveNodeOverlaps(enforcedPositions, collapsedGroupIds, GROUP_R);

    // Compute fading-out and fading-in node sets for animation
    const newVisibleIds = new Set(visibleNodes.map((n) => n.id));
    const oldVisibleIds = new Set(state.visibleNodes.map((n) => n.id));

    const fadingOutNodeIds = state.visibleNodes
      .filter((n) => !newVisibleIds.has(n.id))
      .map((n) => n.id);
    const fadingOutPositions: Record<string, Position> = {};
    fadingOutNodeIds.forEach((id) => { if (state.positions[id]) fadingOutPositions[id] = state.positions[id]; });

    const fadingInNodeIds = visibleNodes
      .filter((n) => !oldVisibleIds.has(n.id))
      .map((n) => n.id);

    set({ activeOwners, visibleNodes, visibleEdges, positions: finalPositions, laneMetrics, selectedNodeId,
      fadingOutNodeIds, fadingOutPositions, fadingInNodeIds });

    if (fadingOutNodeIds.length > 0) setTimeout(() => set({ fadingOutNodeIds: [], fadingOutPositions: {} }), 350);
    if (fadingInNodeIds.length > 0) setTimeout(() => set({ fadingInNodeIds: [] }), 300);
  },

  // ── toggleAllOwners ───────────────────────────────────────────────────────

  /**
   * toggleAllOwners — selects or deselects every owner at once.
   * Recomputes positions using the same merge strategy as toggleOwner.
   */
  toggleAllOwners: () => {
    const state = get();
    const allOwners = [...new Set(state.allNodes.map((node) => node.owner))];
    const allActive = allOwners.every((owner) => state.activeOwners.has(owner));

    const activeOwners = allActive ? new Set<string>() : new Set(allOwners);

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    const { positions: freshPositions, laneMetrics } = derivePositions(
      visibleNodes, visibleEdges, state.viewMode, activeOwners, state.allNodes, state.phases, state.groups
    );
    const positions: Record<string, Position> = { ...freshPositions };
    // Always use freshPositions for all visible nodes — full reflow in both directions.

    const enforcedPositions2 = state.phases.length > 0
      ? enforceAllPhaseBoundaries(positions, state.phases, state.groups, GROUP_R,
          state.viewMode === 'lanes' ? LANE_LABEL_W : 0)
      : positions;
    const collapsedGroupIds2 = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    const finalPositions = resolveNodeOverlaps(enforcedPositions2, collapsedGroupIds2, GROUP_R);

    const newVisibleIds = new Set(visibleNodes.map((n) => n.id));
    const oldVisibleIds = new Set(state.visibleNodes.map((n) => n.id));

    const fadingOutNodeIds = state.visibleNodes
      .filter((n) => !newVisibleIds.has(n.id))
      .map((n) => n.id);
    const fadingOutPositions: Record<string, Position> = {};
    fadingOutNodeIds.forEach((id) => { if (state.positions[id]) fadingOutPositions[id] = state.positions[id]; });

    const fadingInNodeIds = visibleNodes
      .filter((n) => !oldVisibleIds.has(n.id))
      .map((n) => n.id);

    set({ activeOwners, visibleNodes, visibleEdges, positions: finalPositions, laneMetrics, selectedNodeId: null,
      fadingOutNodeIds, fadingOutPositions, fadingInNodeIds });

    if (fadingOutNodeIds.length > 0) setTimeout(() => set({ fadingOutNodeIds: [], fadingOutPositions: {} }), 350);
    if (fadingInNodeIds.length > 0) setTimeout(() => set({ fadingInNodeIds: [] }), 300);
  },

  // ── rebuildGraph ──────────────────────────────────────────────────────────

  /**
   * rebuildGraph — recomputes layout and visibility from scratch.
   *
   * Called after loading data, changing owners, or resetting layout.
   * Does NOT preserve cached positions — use setViewMode for cached switching.
   */
  rebuildGraph: () => {
    const state = get();

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    const { positions: rawPositions, laneMetrics } = derivePositions(
      visibleNodes, visibleEdges, state.viewMode, state.activeOwners, state.allNodes, state.phases, state.groups
    );

    const enforcedPositions = state.phases.length > 0
      ? enforceAllPhaseBoundaries(
          rawPositions, state.phases, state.groups, GROUP_R,
          state.viewMode === 'lanes' ? LANE_LABEL_W : 0
        )
      : rawPositions;

    // Guarantee zero overlaps after a fresh layout.
    // resolveNodeOverlaps runs up to 120 pairwise-separation passes to push apart any
    // remaining collisions — residual overlaps can occur when groups are present,
    // when phase enforcement shifts nodes, or in dense disconnected-component stacks.
    const collapsedGroupIds = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    const positions = resolveNodeOverlaps(enforcedPositions, collapsedGroupIds, GROUP_R);

    set({ visibleNodes, visibleEdges, positions, laneMetrics });
  },

  // ── enterFocusMode ────────────────────────────────────────────────────────

  /**
   * enterFocusMode — zooms into one node's immediate neighborhood.
   *
   * Captures a snapshot of the current state so we can restore it exactly on exit.
   * Then filters visibility to only the focused node + its parents and children.
   */
  enterFocusMode: (nodeId: string) => {
    const state = get();
    const focusedNode = state.allNodes.find((node) => node.id === nodeId);
    if (!focusedNode) return;

    // When re-focusing from within focus mode, keep the ORIGINAL pre-focus snapshot
    // so that exit focus mode always restores to the full graph, not a previous
    // focus neighborhood. Only capture a new snapshot on the first entry.
    const preFocusSnapshot: FocusSnapshot =
      state.focusMode && state.preFocusSnapshot
        ? state.preFocusSnapshot
        : {
            viewModeAtEnter: state.viewMode,
            positions: { ...state.positions },
            laneMetrics: { ...state.laneMetrics },
            transform: { ...state.transform },
            visibleNodes: [...state.visibleNodes],
            visibleEdges: [...state.visibleEdges],
          };

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, true, nodeId, state.groups, 'neighbors'
    );

    const { positions, laneMetrics } = derivePositions(
      visibleNodes, visibleEdges, state.viewMode, state.activeOwners, state.allNodes
    );

    set({ focusMode: true, focusNodeId: nodeId, focusDepth: 'neighbors', selectedNodeId: nodeId, hoveredNodeId: null, preFocusSnapshot, visibleNodes, visibleEdges, positions, laneMetrics });
    setTimeout(() => get().fitToScreen(), 60);
  },

  // ── exitFocusMode ─────────────────────────────────────────────────────────

  /**
   * exitFocusMode — restores the graph to the state it was in before focus was entered.
   *
   * If the view mode changed while in focus, we skip restoring the old snapshot
   * (it would conflict with the new view mode) and just rebuild fresh.
   */
  exitFocusMode: () => {
    const state = get();
    const snapshot = state.preFocusSnapshot;

    if (snapshot && snapshot.viewModeAtEnter === state.viewMode) {
      // Re-derive visibility from the current allNodes/groups state rather than
      // restoring the stale snapshot nodes. This correctly handles any group
      // collapse/expand changes made during focus mode, preventing nodes from
      // disappearing or appearing outside their groups on exit.
      const { visibleNodes, visibleEdges } = deriveVisibility(
        state.allNodes, state.allEdges, state.activeOwners, false, null, state.groups
      );
      set({
        focusMode: false,
        focusNodeId: null,
        focusDepth: 'neighbors',
        hoveredNodeId: null,
        preFocusSnapshot: null,
        visibleNodes,
        visibleEdges,
        positions: snapshot.positions,
        laneMetrics: snapshot.laneMetrics,
        flyTarget: snapshot.transform,
      });
    } else {
      // View mode changed while in focus — discard snapshot, rebuild fresh.
      set({ focusMode: false, focusNodeId: null, focusDepth: 'neighbors', hoveredNodeId: null, preFocusSnapshot: null });
      get().rebuildGraph();
      setTimeout(() => get().fitToScreen(), 60);
    }
  },

  // ── enterOwnerFocus ───────────────────────────────────────────────────────

  /**
   * enterOwnerFocus — activates Owner Focus Mode for the given owner lane.
   *
   * Computes upstream and downstream cross-lane nodes, hides entirely isolated
   * owner lanes (to compact the spatial layout), saves a snapshot for restore,
   * and re-derives visibility and positions.
   */
  enterOwnerFocus: (owner: string) => {
    const state = get();

    // IDs of nodes belonging to the focused owner
    const focusedOwnerNodeIds = new Set(
      state.allNodes.filter((n) => n.owner === owner).map((n) => n.id)
    );

    // Upstream: nodes in OTHER owner lanes that focused-owner nodes depend on
    const upstreamNodeIds = new Set<string>();
    state.allNodes.forEach((n) => {
      if (n.owner === owner) {
        n.dependencies.forEach((dep) => {
          const depNode = state.allNodes.find((d) => d.id === dep);
          if (depNode && depNode.owner !== owner) upstreamNodeIds.add(dep);
        });
      }
    });

    // Downstream: nodes in OTHER owner lanes that depend on focused-owner nodes
    const downstreamNodeIds = new Set<string>();
    state.allNodes.forEach((n) => {
      if (n.owner !== owner && n.dependencies.some((dep) => focusedOwnerNodeIds.has(dep))) {
        downstreamNodeIds.add(n.id);
      }
    });

    // Connected owners = focused owner + any owner with at least one upstream/downstream node
    const connectedOwners = new Set<string>([owner]);
    [...upstreamNodeIds, ...downstreamNodeIds].forEach((id) => {
      const n = state.allNodes.find((x) => x.id === id);
      if (n) connectedOwners.add(n.owner);
    });

    // Snapshot current state so we can restore exactly on exit.
    // If already in owner focus (switching owners), preserve the ORIGINAL snapshot
    // so exit always returns to the state before any owner focus was entered.
    const existingSnap = state.preLaneFocusSnapshot;
    // When entering from within node focus, save the full-graph positions (from preFocusSnapshot)
    // rather than the subgraph positions currently in state.positions. Those subgraph positions
    // would be invalid for the full owner-filter node set restored on exit.
    const basePositions = !existingSnap && state.focusMode && state.preFocusSnapshot
      ? state.preFocusSnapshot.positions
      : state.positions;
    const baseLaneMetrics = !existingSnap && state.focusMode && state.preFocusSnapshot
      ? state.preFocusSnapshot.laneMetrics
      : state.laneMetrics;
    const preLaneFocusSnapshot: OwnerFocusSnapshot = {
      activeOwners:     existingSnap ? existingSnap.activeOwners     : new Set(state.activeOwners),
      positions:        existingSnap ? existingSnap.positions        : { ...basePositions },
      laneMetrics:      existingSnap ? existingSnap.laneMetrics      : { ...baseLaneMetrics },
      transform:        existingSnap ? existingSnap.transform        : { ...state.transform },
      focusMode:        existingSnap ? existingSnap.focusMode        : state.focusMode,
      focusNodeId:      existingSnap ? existingSnap.focusNodeId      : state.focusNodeId,
      focusDepth:       existingSnap ? existingSnap.focusDepth       : state.focusDepth,
      preFocusSnapshot: existingSnap ? existingSnap.preFocusSnapshot : state.preFocusSnapshot,
    };

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, connectedOwners, false, null, state.groups
    );
    const { positions, laneMetrics } = derivePositions(
      visibleNodes, visibleEdges, state.viewMode, connectedOwners, state.allNodes
    );

    set({ suppressEntranceAnimation: true });
    setTimeout(() => set({ suppressEntranceAnimation: false }), 100);

    set({
      focusedOwner: owner,
      preLaneFocusSnapshot,
      activeOwners: connectedOwners,
      visibleNodes,
      visibleEdges,
      positions,
      laneMetrics,
      // Clear node focus — owner focus overrides it; state is saved in the snapshot
      focusMode: false,
      focusNodeId: null,
      focusDepth: 'neighbors',
      preFocusSnapshot: null,
    });

    setTimeout(() => get().fitToScreen(), 60);
  },

  // ── exitOwnerFocus ────────────────────────────────────────────────────────

  /**
   * exitOwnerFocus — restores the graph to the state it was in before owner focus was entered.
   */
  exitOwnerFocus: () => {
    const state = get();
    const snap = state.preLaneFocusSnapshot;
    if (!snap) return;

    set({ suppressEntranceAnimation: true });
    setTimeout(() => set({ suppressEntranceAnimation: false }), 100);

    if (snap.focusMode && snap.focusNodeId) {
      // Owner focus was entered from within node focus mode — restore it.
      // Re-derive the focus neighborhood visibility and fresh positions.
      const { visibleNodes, visibleEdges } = deriveVisibility(
        state.allNodes, state.allEdges, snap.activeOwners,
        true, snap.focusNodeId, state.groups, snap.focusDepth
      );
      const { positions, laneMetrics } = derivePositions(
        visibleNodes, visibleEdges, state.viewMode, snap.activeOwners, state.allNodes
      );
      set({
        focusedOwner: null,
        preLaneFocusSnapshot: null,
        activeOwners: snap.activeOwners,
        focusMode: true,
        focusNodeId: snap.focusNodeId,
        focusDepth: snap.focusDepth,
        preFocusSnapshot: snap.preFocusSnapshot,
        visibleNodes,
        visibleEdges,
        positions,
        laneMetrics,
        flyTarget: null,
      });
      setTimeout(() => get().fitToScreen(), 60);
    } else {
      const { visibleNodes, visibleEdges } = deriveVisibility(
        state.allNodes, state.allEdges, snap.activeOwners, false, null, state.groups
      );
      set({
        focusedOwner: null,
        preLaneFocusSnapshot: null,
        activeOwners: snap.activeOwners,
        visibleNodes,
        visibleEdges,
        positions: snap.positions,
        laneMetrics: snap.laneMetrics,
        transform: snap.transform,
        flyTarget: null, // stop any in-flight fitToScreen animation from enterOwnerFocus
      });
    }
  },

  // ── saveLayoutToCache ─────────────────────────────────────────────────────
  saveLayoutToCache: () => {
    const state = get();
    if (state.focusMode) return; // Don't cache focus-mode layouts

    set({
      layoutCache: {
        ...state.layoutCache,
        [state.viewMode]: {
          positions: { ...state.positions },
          transform: { ...state.transform },
        },
      },
    });
  },

  // ── saveNamedLayout ───────────────────────────────────────────────────────

  /**
   * saveNamedLayout — persists a named layout snapshot to localStorage.
   *
   * Saved layouts survive browser refresh. They are browser-specific (localStorage
   * is not shared between browsers or devices).
   */
  saveNamedLayout: (name: string) => {
    const state = get();
    const snapshot: LayoutSnapshot = {
      positions: { ...state.positions },
      transform: { ...state.transform },
    };

    const savedLayouts = JSON.parse(localStorage.getItem('flowgraph-layouts') ?? '[]');
    savedLayouts.push({
      name,
      savedAt: new Date().toISOString(),
      viewMode: state.viewMode,
      snapshot,
    });
    localStorage.setItem('flowgraph-layouts', JSON.stringify(savedLayouts));
  },

  // ── loadNamedLayout ───────────────────────────────────────────────────────
  loadNamedLayout: (snapshot: LayoutSnapshot, viewMode: ViewMode) => {
    const state = get();
    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, false, null, state.groups
    );

    const enforcedPositions = viewMode === 'lanes' && state.phases.length > 0
      ? enforceAllPhaseBoundaries(snapshot.positions, state.phases, state.groups, GROUP_R, LANE_LABEL_W)
      : snapshot.positions;

    set({
      positions: enforcedPositions,
      viewMode,
      visibleNodes,
      visibleEdges,
      focusMode: false,
      focusNodeId: null,
    });
    set({ flyTarget: snapshot.transform });
  },

  // ── fitToScreen ───────────────────────────────────────────────────────────

  /**
   * fitToScreen — computes a transform that centers and scales the graph to fill the viewport.
   *
   * This is called after loading data or resetting layout. The canvas element's
   * dimensions are read from the DOM to compute the correct scale and offset.
   */
  fitToScreen: (animate = true) => {
    const state = get();
    if (Object.keys(state.positions).length === 0) return;

    const canvasEl = document.getElementById('canvas-wrap');
    if (!canvasEl) return;

    const { width: canvasW, height: canvasH } = canvasEl.getBoundingClientRect();

    // When phases are collapsed, the accordion shifts nodes left and hides nodes inside
    // collapsed bands. Use the phase-adjusted positions so the bounding box matches
    // what is actually visible on screen.
    let displayPositions = state.positions;
    let hiddenIds = new Set<string>();
    if (state.collapsedPhaseIds.length > 0 && state.phases.length > 0) {
      const adjusted = computePhaseAdjustedPositions(
        state.phases, state.positions, state.collapsedPhaseIds, NODE_W,
        state.viewMode === 'lanes' ? LANE_LABEL_W : undefined,
      );
      displayPositions = adjusted.adjustedPositions;
      hiddenIds = adjusted.hiddenNodeIds;
    }

    // Find the bounding box of all visible (non-hidden) nodes.
    // In lanes view, lane labels sit at x=0..LANE_LABEL_W, so we extend minX to 0
    // to prevent them from being clipped when fitting to screen.
    const visiblePositions = Object.entries(displayPositions)
      .filter(([id]) => !hiddenIds.has(id))
      .map(([, pos]) => pos);
    if (visiblePositions.length === 0) return;
    const xs = visiblePositions.map((pos) => pos.x);
    const ys = visiblePositions.map((pos) => pos.y);
    const minX = state.viewMode === 'lanes' ? 0 : Math.min(...xs);
    const maxX = Math.max(...xs) + NODE_W;
    const minY = Math.min(...ys);
    const maxY = Math.max(...ys) + NODE_H;

    const graphW = maxX - minX;
    const graphH = maxY - minY;

    const padding = 60; // px padding around the fitted graph
    const scaleX = (canvasW - padding * 2) / graphW;
    const scaleY = (canvasH - padding * 2) / graphH;
    const scale = Math.min(scaleX, scaleY, 1.5); // Cap zoom at 150% to avoid too-close view

    const offsetX = (canvasW - graphW * scale) / 2 - minX * scale;
    const offsetY = (canvasH - graphH * scale) / 2 - minY * scale;

    const target = { x: offsetX, y: offsetY, k: scale };
    if (animate) {
      set({ flyTarget: target });
    } else {
      set({ transform: target });
    }
  },

  // ── createGroup ───────────────────────────────────────────────────────────
  createGroup: (childNodeIds, childGroupIds, data) => {
    const state = get();

    const undoSnapshot: UndoSnapshot = {
      nodes: [...state.allNodes],
      positions: { ...state.positions },
      groups: [...state.groups],
      laneMetrics: { ...state.laneMetrics },
    };

    const id = generateGroupId(state.groups);
    const owners = deriveGroupOwners(childNodeIds, childGroupIds, state.allNodes, state.groups);

    // Place the group polygon at the centroid of its children
    const childPositions = childNodeIds
      .map((nid) => state.positions[nid])
      .filter(Boolean) as { x: number; y: number }[];
    // Also include positions from child groups
    childGroupIds.forEach((gid) => {
      if (state.positions[gid]) childPositions.push(state.positions[gid]);
    });

    const cx = childPositions.length > 0
      ? childPositions.reduce((s, p) => s + p.x, 0) / childPositions.length
      : 200;
    const cy = childPositions.length > 0
      ? childPositions.reduce((s, p) => s + p.y, 0) / childPositions.length
      : 200;

    const newGroup: GraphGroup = {
      id,
      name: data.name,
      description: data.description,
      owners,
      childNodeIds,
      childGroupIds,
      collapsed: false,
    };

    const groups = [...state.groups, newGroup];
    const positions = { ...state.positions, [id]: { x: cx, y: cy } };

    // Adopt the phase shared by children: add the new group to that phase's groupIds
    const childPhaseId = (() => {
      for (const nid of childNodeIds) {
        const ph = state.phases.find((p) => p.nodeIds.includes(nid));
        if (ph) return ph.id;
      }
      for (const gid of childGroupIds) {
        const ph = state.phases.find((p) => (p.groupIds ?? []).includes(gid));
        if (ph) return ph.id;
      }
      return null;
    })();
    const phases = childPhaseId
      ? state.phases.map((p) =>
          p.id === childPhaseId
            ? { ...p, groupIds: [...(p.groupIds ?? []), id] }
            : p
        )
      : state.phases;

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, state.focusMode, state.focusNodeId, groups
    );

    set({
      groups,
      positions,
      phases,
      visibleNodes,
      visibleEdges,
      multiSelectIds: [],
      designDirty: true,
      undoStack: [...state.undoStack, undoSnapshot].slice(-50),
      redoStack: [],
    });
  },

  // ── updateGroup ───────────────────────────────────────────────────────────
  updateGroup: (id, changes) => {
    const state = get();
    const groups = state.groups.map((g) => (g.id === id ? { ...g, ...changes } : g));

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, state.focusMode, state.focusNodeId, groups
    );

    set({ groups, visibleNodes, visibleEdges, designDirty: true });
  },

  // ── deleteGroup ───────────────────────────────────────────────────────────
  deleteGroup: (id, dissolve = true) => {
    const state = get();

    const undoSnapshot: UndoSnapshot = {
      nodes: [...state.allNodes],
      positions: { ...state.positions },
      groups: [...state.groups],
      laneMetrics: { ...state.laneMetrics },
    };

    let groups = state.groups.filter((g) => g.id !== id);
    const positions = { ...state.positions };

    if (!dissolve) {
      // Also remove all descendant nodes and groups
      const toDelete = getAllDescendantNodeIds(id, state.groups);
      const groupsToDelete = new Set(getAllDescendantGroupIds(id, state.groups));
      groups = groups.filter((g) => !groupsToDelete.has(g.id));
      let allNodes = state.allNodes.filter((n) => !toDelete.includes(n.id));
      allNodes = allNodes.map((n) => ({
        ...n,
        dependencies: n.dependencies.filter((dep) => !toDelete.includes(dep)),
      }));
      toDelete.forEach((nid) => delete positions[nid]);
      groupsToDelete.forEach((gid) => delete positions[gid]);
      delete positions[id];

      // Remove the deleted group and all its descendants from any phase they belong to
      const allDeletedGroupIds = new Set([id, ...groupsToDelete]);
      const phasesAfterDelete = state.phases.map((p) => ({
        ...p,
        groupIds: (p.groupIds ?? []).filter((gid) => !allDeletedGroupIds.has(gid)),
      }));

      const allEdges = rebuildEdgesFromNodes(allNodes);
      const { visibleNodes, visibleEdges } = deriveVisibility(
        allNodes, allEdges, state.activeOwners, state.focusMode, state.focusNodeId, groups
      );
      set({
        allNodes, allEdges, visibleNodes, visibleEdges, groups, positions,
        phases: phasesAfterDelete,
        designDirty: true,
        undoStack: [...state.undoStack, undoSnapshot].slice(-50),
        redoStack: [],
      });
      return;
    }

    // Dissolve: children remain as standalone; just remove the group entry and its position
    delete positions[id];
    // Remove from any parent group's childGroupIds
    groups = groups.map((g) => ({
      ...g,
      childGroupIds: g.childGroupIds.filter((gid) => gid !== id),
    }));

    // Remove the group from any phase it belongs to
    const phases = state.phases.map((p) => ({
      ...p,
      groupIds: (p.groupIds ?? []).filter((gid) => gid !== id),
    }));

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, state.focusMode, state.focusNodeId, groups
    );

    set({
      groups, positions, visibleNodes, visibleEdges, phases,
      designDirty: true,
      undoStack: [...state.undoStack, undoSnapshot].slice(-50),
      redoStack: [],
    });
  },

  // ── toggleGroupCollapse ───────────────────────────────────────────────────
  toggleGroupCollapse: (id) => {
    const state = get();
    const group = state.groups.find((g) => g.id === id);
    const willCollapse = group && !group.collapsed;

    const groups = state.groups.map((g) =>
      g.id === id ? { ...g, collapsed: !g.collapsed } : g
    );

    // When collapsing, recalculate the polygon center from current child positions
    // so the polygon appears where the content actually is, not at the stale creation-time centroid.
    let positions = state.positions;
    if (willCollapse && group) {
      // Gather center points of all descendant nodes (node positions are top-left, so add half-size)
      const descendantNodeIds = getAllDescendantNodeIds(id, state.groups);
      const pts: { x: number; y: number }[] = [
        ...descendantNodeIds
          .map((nid) => state.positions[nid])
          .filter((p): p is { x: number; y: number } => !!p)
          .map((p) => ({ x: p.x + NODE_W / 2, y: p.y + NODE_H / 2 })),
        // Child group positions are already centers
        ...group.childGroupIds
          .map((gid) => state.positions[gid])
          .filter((p): p is { x: number; y: number } => !!p),
      ];
      if (pts.length > 0) {
        const cx = pts.reduce((s, p) => s + p.x, 0) / pts.length;
        const cy = pts.reduce((s, p) => s + p.y, 0) / pts.length;
        positions = { ...state.positions, [id]: { x: cx, y: cy } };
      }
    }

    const { visibleNodes, visibleEdges } = deriveVisibility(
      state.allNodes, state.allEdges, state.activeOwners, state.focusMode, state.focusNodeId, groups
    );

    set({ groups, positions, visibleNodes, visibleEdges, designDirty: true });

    // Both collapse and expand may create overlaps: collapse places a polygon at the
    // children's centroid (which may land on a neighbour), expand reveals children
    // that may need to spread out. Run overlap resolution in both cases.
    get().resolveOverlaps();
  },

  // ── setSelectedGroup ──────────────────────────────────────────────────────
  setSelectedGroup: (id) => set((s) => ({ selectedGroupId: id, selectedNodeId: s.focusMode && s.focusNodeId ? s.focusNodeId : null, selectedPhaseId: null, multiSelectIds: [] })),

  // ── toggleMultiSelect ─────────────────────────────────────────────────────
  toggleMultiSelect: (id) => {
    const state = get();
    const ids = state.multiSelectIds;
    set({
      multiSelectIds: ids.includes(id) ? ids.filter((x) => x !== id) : [...ids, id],
    });
  },

  // ── clearMultiSelect ──────────────────────────────────────────────────────
  clearMultiSelect: () => set({ multiSelectIds: [] }),

  // ── setMultiSelectIds ─────────────────────────────────────────────────────
  setMultiSelectIds: (ids) => set({
    multiSelectIds: ids,
    selectedNodeId: ids.length === 1 ? ids[0] : null,
    selectedGroupId: null,
  }),

  // ── toggleMarqueeMode ─────────────────────────────────────────────────────
  toggleMarqueeMode: () => set((s) => ({ marqueeMode: !s.marqueeMode, panMode: false })),

  // ── togglePanMode ─────────────────────────────────────────────────────────
  togglePanMode: () => set((s) => ({ panMode: !s.panMode, marqueeMode: false })),

  // ── createPhase ───────────────────────────────────────────────────────────
  createPhase: (nodeIds, data, groupIds = []) => {
    const state = get();

    // Expand groups to include all nested descendant groups and their nodes
    const allGroupIds = [...new Set([
      ...groupIds,
      ...groupIds.flatMap((gid) => getAllDescendantGroupIds(gid, state.groups)),
    ])];
    const allGroupNodeIds = [...new Set(
      groupIds.flatMap((gid) => getAllDescendantNodeIds(gid, state.groups)),
    )];
    const allNodeIds = [...new Set([...nodeIds, ...allGroupNodeIds])];

    const undoSnapshot: UndoSnapshot = {
      nodes: [...state.allNodes],
      positions: { ...state.positions },
      groups: [...state.groups],
      phases: [...state.phases],
      laneMetrics: { ...state.laneMetrics },
    };

    const nextSeq = state.phases.length > 0
      ? Math.max(...state.phases.map((p) => p.sequence)) + 1
      : 0;
    const colorIdx = state.phases.length % PHASE_PALETTE.length;
    const id = `PHASE-${String(state.phases.length + 1).padStart(2, '0')}`;

    const newPhase: GraphPhase = {
      id,
      name: data.name,
      description: data.description,
      color: data.color ?? PHASE_PALETTE[colorIdx],
      nodeIds: allNodeIds,
      groupIds: allGroupIds,
      sequence: nextSeq,
    };

    // Remove these nodes/groups from any existing phase
    const phases = state.phases.map((p) => ({
      ...p,
      nodeIds: p.nodeIds.filter((nid) => !allNodeIds.includes(nid)),
      groupIds: (p.groupIds ?? []).filter((gid) => !allGroupIds.includes(gid)),
    }));

    const allPhasesAfterCreate = [...phases, newPhase];
    const adjustedPositions = pushNodesOutOfPhaseBand(
      state.positions,
      allPhasesAfterCreate,
      newPhase.id,
      NODE_W
    );
    const collapsedGroupIds1 = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    const resolvedPositions = resolveNodeOverlaps(adjustedPositions, collapsedGroupIds1, GROUP_R);

    const otherMode: ViewMode = state.viewMode === 'dag' ? 'lanes' : 'dag';
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { [otherMode]: _dropped, ...cacheWithoutOther } = state.layoutCache;
    const updatedCache: Record<string, LayoutSnapshot> = {
      ...cacheWithoutOther,
      [state.viewMode]: { positions: resolvedPositions, transform: state.transform },
    };

    set({
      phases: allPhasesAfterCreate,
      positions: resolvedPositions,
      layoutCache: updatedCache,
      designDirty: true,
      undoStack: [...state.undoStack, undoSnapshot].slice(-50),
      redoStack: [],
    });
  },

  // ── updatePhase ───────────────────────────────────────────────────────────
  updatePhase: (id, changes) => {
    const state = get();
    const phases = state.phases.map((p) => (p.id === id ? { ...p, ...changes } : p));
    set({ phases, designDirty: true });
  },

  // ── movePhase ─────────────────────────────────────────────────────────────
  movePhase: (id, direction) => {
    const { phases } = get();
    const sorted = [...phases].sort((a, b) => a.sequence - b.sequence);
    const idx = sorted.findIndex((p) => p.id === id);
    const swapIdx = direction === 'left' ? idx - 1 : idx + 1;
    if (swapIdx < 0 || swapIdx >= sorted.length) return;
    const a = sorted[idx];
    const b = sorted[swapIdx];
    const updated = phases.map((p) => {
      if (p.id === a.id) return { ...p, sequence: b.sequence };
      if (p.id === b.id) return { ...p, sequence: a.sequence };
      return p;
    });
    set({ phases: updated, designDirty: true });
  },

  // ── deletePhase ───────────────────────────────────────────────────────────
  deletePhase: (id) => {
    const state = get();

    const undoSnapshot: UndoSnapshot = {
      nodes: [...state.allNodes],
      positions: { ...state.positions },
      groups: [...state.groups],
      phases: [...state.phases],
      laneMetrics: { ...state.laneMetrics },
    };

    const phases = state.phases.filter((p) => p.id !== id);
    set({
      phases,
      selectedPhaseId: state.selectedPhaseId === id ? null : state.selectedPhaseId,
      focusedPhaseId: state.focusedPhaseId === id ? null : state.focusedPhaseId,
      collapsedPhaseIds: state.collapsedPhaseIds.filter((x) => x !== id),
      designDirty: true,
      undoStack: [...state.undoStack, undoSnapshot].slice(-50),
      redoStack: [],
    });
  },

  // ── assignNodesToPhase ────────────────────────────────────────────────────
  assignNodesToPhase: (nodeIds, phaseId) => {
    const state = get();
    const phases = state.phases.map((p) => {
      if (p.id === phaseId) {
        // Add without duplication
        const merged = [...new Set([...p.nodeIds, ...nodeIds])];
        return { ...p, nodeIds: merged };
      }
      // Remove from all other phases
      return { ...p, nodeIds: p.nodeIds.filter((nid) => !nodeIds.includes(nid)) };
    });

    // Push non-members out of the (potentially expanded) phase band
    const adjustedPositions = pushNodesOutOfPhaseBand(state.positions, phases, phaseId, NODE_W);
    const collapsedGroupIds2 = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    const resolvedPositions2 = resolveNodeOverlaps(adjustedPositions, collapsedGroupIds2, GROUP_R);

    const otherMode: ViewMode = state.viewMode === 'dag' ? 'lanes' : 'dag';
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { [otherMode]: _dropped, ...cacheWithoutOther } = state.layoutCache;
    const updatedCache: Record<string, LayoutSnapshot> = {
      ...cacheWithoutOther,
      [state.viewMode]: { positions: resolvedPositions2, transform: state.transform },
    };

    set({ phases, positions: resolvedPositions2, layoutCache: updatedCache, designDirty: true });
  },

  // ── removeNodesFromPhase ──────────────────────────────────────────────────
  removeNodesFromPhase: (nodeIds) => {
    const state = get();
    const phases = state.phases.map((p) => ({
      ...p,
      nodeIds: p.nodeIds.filter((nid) => !nodeIds.includes(nid)),
    }));
    set({ phases, designDirty: true });
  },

  // ── assignGroupsToPhase ───────────────────────────────────────────────────
  assignGroupsToPhase: (groupIds, phaseId) => {
    const state = get();

    // Expand each group to include all nested descendant groups and their nodes
    const allGroupIds = [...new Set([
      ...groupIds,
      ...groupIds.flatMap((gid) => getAllDescendantGroupIds(gid, state.groups)),
    ])];
    const allNodeIds = [...new Set(
      groupIds.flatMap((gid) => getAllDescendantNodeIds(gid, state.groups)),
    )];

    const phases = state.phases.map((p) => {
      if (p.id === phaseId) {
        const mergedGroups = [...new Set([...(p.groupIds ?? []), ...allGroupIds])];
        const mergedNodes = [...new Set([...p.nodeIds, ...allNodeIds])];
        return { ...p, groupIds: mergedGroups, nodeIds: mergedNodes };
      }
      return {
        ...p,
        groupIds: (p.groupIds ?? []).filter((gid) => !allGroupIds.includes(gid)),
        nodeIds: p.nodeIds.filter((nid) => !allNodeIds.includes(nid)),
      };
    });

    const adjustedPositions = pushNodesOutOfPhaseBand(
      state.positions, phases, phaseId, NODE_W, state.groups, GROUP_R,
      state.viewMode === 'lanes' ? LANE_LABEL_W : undefined
    );
    const collapsedGroupIds3 = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    const resolvedPositions3 = resolveNodeOverlaps(adjustedPositions, collapsedGroupIds3, GROUP_R);

    const otherMode: ViewMode = state.viewMode === 'dag' ? 'lanes' : 'dag';
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { [otherMode]: _dropped, ...cacheWithoutOther } = state.layoutCache;
    const updatedCache: Record<string, LayoutSnapshot> = {
      ...cacheWithoutOther,
      [state.viewMode]: { positions: resolvedPositions3, transform: state.transform },
    };

    set({ phases, positions: resolvedPositions3, layoutCache: updatedCache, designDirty: true });
  },

  // ── removeGroupsFromPhase ─────────────────────────────────────────────────
  removeGroupsFromPhase: (groupIds) => {
    const state = get();
    const phases = state.phases.map((p) => ({
      ...p,
      groupIds: (p.groupIds ?? []).filter((gid) => !groupIds.includes(gid)),
    }));
    set({ phases, designDirty: true });
  },

  // ── settleAllPhases ───────────────────────────────────────────────────────
  settleAllPhases: () => {
    const state = get();
    if (state.phases.length === 0) return;
    let settled: Record<string, { x: number; y: number }>;
    if (state.viewMode === 'lanes') {
      settled = enforceAllPhaseBoundaries(state.positions, state.phases, state.groups, GROUP_R, LANE_LABEL_W);
    } else {
      // DAG mode: chain pushNodesOutOfPhaseBand for each phase sorted by sequence
      const sorted = [...state.phases].sort((a, b) => a.sequence - b.sequence);
      settled = state.positions;
      for (const phase of sorted) {
        settled = pushNodesOutOfPhaseBand(settled, state.phases, phase.id, NODE_W, state.groups, GROUP_R, undefined);
      }
    }
    set({ positions: settled, designDirty: true });
  },

  // ── reorderPhasesByPosition ───────────────────────────────────────────────
  reorderPhasesByPosition: () => {
    const { phases, positions } = get();
    const withMeanX = phases.map((ph) => {
      const pts = ph.nodeIds.map((nid) => positions[nid]).filter(Boolean) as { x: number; y: number }[];
      const meanX = pts.length > 0 ? pts.reduce((s, p) => s + p.x, 0) / pts.length : Infinity;
      return { id: ph.id, meanX };
    });
    withMeanX.sort((a, b) => a.meanX - b.meanX);
    const updated = phases.map((ph) => ({
      ...ph,
      sequence: withMeanX.findIndex((w) => w.id === ph.id),
    }));
    set({ phases: updated, designDirty: true });
  },

  // ── resolveOverlaps ───────────────────────────────────────────────────────
  resolveOverlaps: () => {
    const state = get();
    if (Object.keys(state.positions).length < 2) return;
    const collapsedGroupIds = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    const resolved = resolveNodeOverlaps(state.positions, collapsedGroupIds, GROUP_R);
    set({ positions: resolved, designDirty: true });
  },

  // ── settleAndResolve ──────────────────────────────────────────────────────
  settleAndResolve: (anchorIds?: Set<string>) => {
    const state = get();
    if (Object.keys(state.positions).length < 2) return;

    // Step 1 — phase band enforcement (same logic as settleAllPhases)
    let positions = state.positions;
    if (state.phases.length > 0) {
      if (state.viewMode === 'lanes') {
        positions = enforceAllPhaseBoundaries(positions, state.phases, state.groups, GROUP_R, LANE_LABEL_W);
      } else {
        const sorted = [...state.phases].sort((a, b) => a.sequence - b.sequence);
        for (const phase of sorted) {
          positions = pushNodesOutOfPhaseBand(positions, state.phases, phase.id, NODE_W, state.groups, GROUP_R, undefined);
        }
      }
    }

    // Step 2 — overlap resolution with legibility padding
    const collapsedGroupIds = new Set(state.groups.filter((g) => g.collapsed).map((g) => g.id));
    positions = resolveNodeOverlaps(
      positions, collapsedGroupIds, GROUP_R,
      LEGIBILITY_PAD_X, LEGIBILITY_PAD_Y,
      anchorIds ?? new Set()
    );

    // Step 3 — clamp Y back to lane bounds in LANES view
    // (overlap resolution may have pushed nodes outside their owner lane)
    if (state.viewMode === 'lanes') {
      const clamped: Record<string, Position> = {};
      Object.entries(positions).forEach(([id, pos]) => {
        const node = state.allNodes.find((n) => n.id === id);
        if (node) {
          const lane = state.laneMetrics[node.owner];
          if (lane) {
            const margin = 6;
            clamped[id] = {
              ...pos,
              y: Math.max(lane.y + margin, Math.min(lane.y + lane.height - NODE_H - margin, pos.y)),
            };
            return;
          }
        }
        clamped[id] = pos;
      });
      positions = clamped;
    }

    set({ positions, designDirty: true });
  },

  // ── setSelectedPhaseId ────────────────────────────────────────────────────
  setSelectedPhaseId: (id) => set((s) => ({ selectedPhaseId: id, selectedNodeId: s.focusMode && s.focusNodeId ? s.focusNodeId : null, selectedGroupId: null })),

  // ── setFocusedPhaseId ─────────────────────────────────────────────────────
  setFocusedPhaseId: (id) => set({ focusedPhaseId: id }),

  // ── collapsePhase ─────────────────────────────────────────────────────────
  collapsePhase: (id) => {
    const state = get();
    if (state.collapsedPhaseIds.includes(id)) return;
    set({ collapsedPhaseIds: [...state.collapsedPhaseIds, id] });
  },

  // ── expandPhase ───────────────────────────────────────────────────────────
  expandPhase: (id) => set((s) => ({
    collapsedPhaseIds: s.collapsedPhaseIds.filter((x) => x !== id),
  })),

  // ── togglePhaseCollapse ───────────────────────────────────────────────────
  togglePhaseCollapse: (id) => {
    const state = get();
    set({
      collapsedPhaseIds: state.collapsedPhaseIds.includes(id)
        ? state.collapsedPhaseIds.filter((x) => x !== id)
        : [...state.collapsedPhaseIds, id],
    });
  },

  // ── collapseAllPhases ─────────────────────────────────────────────────────
  collapseAllPhases: () => set((s) => ({
    collapsedPhaseIds: s.phases.map((p) => p.id),
  })),

  // ── expandAllPhases ───────────────────────────────────────────────────────
  expandAllPhases: () => set({ collapsedPhaseIds: [] }),

  // ── copySelection ─────────────────────────────────────────────────────────
  copySelection: () => {
    const state = get();
    const groupIdSet = new Set(state.groups.map((g) => g.id));

    let nodeIds: string[];
    if (state.multiSelectIds.length > 0) {
      nodeIds = state.multiSelectIds.filter((id) => !groupIdSet.has(id));
    } else if (state.selectedNodeId) {
      nodeIds = [state.selectedNodeId];
    } else {
      return;
    }

    const clipboard = state.allNodes.filter((n) => nodeIds.includes(n.id));
    if (clipboard.length > 0) {
      set({ clipboard });
    }
  },

  // ── pasteClipboard ────────────────────────────────────────────────────────
  pasteClipboard: () => {
    const state = get();
    const { clipboard, allNodes, positions } = state;
    if (clipboard.length === 0) return;

    // Push undo snapshot
    const undoSnapshot: UndoSnapshot = {
      nodes: [...allNodes],
      positions: { ...positions },
      groups: [...state.groups],
      laneMetrics: { ...state.laneMetrics },
    };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);

    // Generate unique new IDs for each clipboard node
    const existingIds = new Set(allNodes.map((n) => n.id));
    const idMap = new Map<string, string>();
    const clipboardIdSet = new Set(clipboard.map((n) => n.id));
    let counter = allNodes.length + 1;

    for (const node of clipboard) {
      while (existingIds.has(`NODE-${String(counter).padStart(2, '0')}`)) {
        counter++;
      }
      const newId = `NODE-${String(counter).padStart(2, '0')}`;
      idMap.set(node.id, newId);
      existingIds.add(newId);
      counter++;
    }

    // Create pasted nodes: new IDs, no edges
    const PASTE_OFFSET = 80;
    const newNodes: GraphNode[] = clipboard.map((node) => ({
      ...node,
      id: idMap.get(node.id)!,
      dependencies: [],
    }));

    // Compute pasted positions offset from originals
    const newPositions: Record<string, Position> = {};
    for (const node of clipboard) {
      const orig = positions[node.id];
      const newId = idMap.get(node.id)!;
      newPositions[newId] = orig
        ? { x: orig.x + PASTE_OFFSET, y: orig.y + PASTE_OFFSET }
        : { x: 200, y: 200 };
    }

    const allNodesNew = [...allNodes, ...newNodes];
    const allEdges = rebuildEdgesFromNodes(allNodesNew);
    const ownerColors = assignOwnerColors([...new Set(allNodesNew.map((n) => n.owner))]);

    // Ensure pasted nodes' owners are visible
    const activeOwners = new Set(state.activeOwners);
    for (const node of newNodes) activeOwners.add(node.owner);

    const { visibleNodes, visibleEdges } = deriveVisibility(
      allNodesNew, allEdges, activeOwners, state.focusMode, state.focusNodeId, state.groups
    );

    const newNodeIds = newNodes.map((n) => n.id);
    set((s) => ({
      allNodes: allNodesNew,
      allEdges,
      visibleNodes,
      visibleEdges,
      positions: { ...positions, ...newPositions },
      ownerColors,
      activeOwners,
      multiSelectIds: newNodeIds,
      selectedNodeId: newNodeIds.length === 1 ? newNodeIds[0] : null,
      selectedGroupId: null,
      designDirty: true,
      undoStack,
      redoStack: [],
      pasteCount: s.pasteCount + 1,
      suppressEntranceAnimation: true,
    }));
    setTimeout(() => set({ suppressEntranceAnimation: false }), 100);
  },

  // ── setOwnerColor ─────────────────────────────────────────────────────────
  setOwnerColor: (owner, color) => {
    set((s) => ({ ownerColors: { ...s.ownerColors, [owner]: color } }));
  },

  // ── renameOwner ───────────────────────────────────────────────────────────
  renameOwner: (oldName, newName) => {
    const trimmed = newName.trim();
    if (!trimmed || trimmed === oldName) return;
    const state = get();

    const allNodes = state.allNodes.map((n) =>
      n.owner === oldName ? { ...n, owner: trimmed } : n
    );

    const ownerColors = { ...state.ownerColors };
    if (ownerColors[oldName] !== undefined) {
      ownerColors[trimmed] = ownerColors[oldName];
      delete ownerColors[oldName];
    }

    const activeOwners = new Set(state.activeOwners);
    if (activeOwners.has(oldName)) {
      activeOwners.delete(oldName);
      activeOwners.add(trimmed);
    }

    const groups = state.groups.map((g) => ({
      ...g,
      owners: g.owners.map((o) => (o === oldName ? trimmed : o)),
    }));

    const { visibleNodes, visibleEdges } = deriveVisibility(
      allNodes, state.allEdges, activeOwners, state.focusMode, state.focusNodeId, groups
    );

    set({ allNodes, ownerColors, activeOwners, groups, visibleNodes, visibleEdges, designDirty: true });
  },

  // ── recolorTag ────────────────────────────────────────────────────────────
  recolorTag: (label, color) => {
    const key = label.toLowerCase();
    set((s) => {
      const updateNodes = (nodes: typeof s.allNodes) =>
        nodes.map((n) => {
          if (!n.tags?.some((t) => t.label.toLowerCase() === key)) return n;
          return { ...n, tags: n.tags.map((t) => t.label.toLowerCase() === key ? { ...t, color } : t) };
        });
      const tagRegistry = s.tagRegistry.map((t) =>
        t.label.toLowerCase() === key ? { ...t, color } : t
      );
      return {
        allNodes: updateNodes(s.allNodes),
        visibleNodes: updateNodes(s.visibleNodes),
        tagRegistry,
        designDirty: true,
      };
    });
  },

  // ── renameTag ─────────────────────────────────────────────────────────────
  renameTag: (oldLabel, newLabel) => {
    const trimmed = newLabel.trim();
    if (!trimmed) return;
    const key = oldLabel.toLowerCase();
    set((s) => {
      const updateNodes = (nodes: typeof s.allNodes) =>
        nodes.map((n) => {
          if (!n.tags?.some((t) => t.label.toLowerCase() === key)) return n;
          return { ...n, tags: n.tags.map((t) => t.label.toLowerCase() === key ? { ...t, label: trimmed } : t) };
        });
      const tagRegistry = s.tagRegistry.map((t) =>
        t.label.toLowerCase() === key ? { ...t, label: trimmed } : t
      );
      return {
        allNodes: updateNodes(s.allNodes),
        visibleNodes: updateNodes(s.visibleNodes),
        tagRegistry,
        designDirty: true,
      };
    });
  },

  // ── addTagToRegistry ──────────────────────────────────────────────────────
  addTagToRegistry: (tag) => {
    set((s) => {
      const key = tag.label.toLowerCase();
      if (s.tagRegistry.some((t) => t.label.toLowerCase() === key)) return s;
      // Also skip if already on any node — it's already in the "global" pool
      const onNode = s.allNodes.some((n) =>
        n.tags?.some((t) => t.label.toLowerCase() === key)
      );
      if (onNode) return s;
      return { tagRegistry: [...s.tagRegistry, tag] };
    });
  },

  // ── removeTagFromRegistry ─────────────────────────────────────────────────
  removeTagFromRegistry: (label) => {
    const key = label.toLowerCase();
    set((s) => ({
      tagRegistry: s.tagRegistry.filter((t) => t.label.toLowerCase() !== key),
    }));
  },

  // ── addOwnerToRegistry ────────────────────────────────────────────────────
  addOwnerToRegistry: (name) => {
    const trimmed = name.trim();
    if (!trimmed) return;
    const key = trimmed.toLowerCase();
    set((s) => {
      // No-op if already on a node or already in registry
      if (s.allNodes.some((n) => n.owner.toLowerCase() === key)) return s;
      if (s.ownerRegistry.some((o) => o.toLowerCase() === key)) return s;
      return { ownerRegistry: [...s.ownerRegistry, trimmed] };
    });
  },

  // ── removeOwnerFromRegistry ───────────────────────────────────────────────
  removeOwnerFromRegistry: (name) => {
    const key = name.toLowerCase();
    set((s) => ({
      ownerRegistry: s.ownerRegistry.filter((o) => o.toLowerCase() !== key),
    }));
  },

  // ── Cinema / Discovery actions ────────────────────────────────────────────

  startDiscovery: (sequence) => {
    set({
      discoveryActive: true,
      discoveryPhase: 'cinema',
      discoverySequence: sequence,
      discoverySceneIndex: 0,
      discoveryVisited: [],
      discoveryHeatmap: {},
    });
  },

  completeDiscovery: () => {
    // Single set() call — one render, no race between roleMap clear and phase update.
    set({ discoveryPhase: 'transition', discoveryRoleMap: {} });
  },

  exitDiscovery: () => {
    set({ discoveryActive: false, discoveryPhase: null, discoveryRoleMap: {} });
    // discoverySequence, discoveryVisited, and discoveryEngagement are
    // intentionally preserved after exit — Phase 2 (Reconstruction) and
    // Phase 3 (Heatmap) read them in a subsequent session.
  },

  setDiscoveryRoleMap: (map) => set({ discoveryRoleMap: map }),

  advanceScene: () => {
    set((s) => {
      const max = (s.discoverySequence?.scenes.length ?? 1) - 1;
      return { discoverySceneIndex: Math.min(s.discoverySceneIndex + 1, max) };
    });
  },

  retreatScene: () => {
    set((s) => ({ discoverySceneIndex: Math.max(s.discoverySceneIndex - 1, 0) }));
  },

  visitNode: (nodeId) => {
    set((s) => {
      if (s.discoveryVisited.includes(nodeId)) return s;
      return { discoveryVisited: [...s.discoveryVisited, nodeId] };
    });
  },

  recordEngagement: (nodeId, score) => {
    set((s) => ({
      discoveryEngagement: {
        ...s.discoveryEngagement,
        [nodeId]: (s.discoveryEngagement[nodeId] ?? 0) + score,
      },
    }));
  },

  startHeatmap: () => {
    set((s) => {
      const normalized = computeNormalizedEngagement(s.discoveryEngagement, s.discoveryVisited);
      const tiers: Record<string, HeatTier> = {};
      for (const id of s.discoveryVisited) {
        tiers[id] = assignHeatTier(normalized[id]);
      }
      return { discoveryHeatmap: normalized, heatTiers: tiers, discoveryPhase: 'heatmap' };
    });
    setTimeout(() => get().fitToScreen(), 60);
  },

  startReconstruction: () => {
    set({ discoveryPhase: 'reconstruction', reconstructionAccuracy: {}, selectedReconstructionChip: null });
  },

  selectReconstructionChip: (nodeId) => {
    set({ selectedReconstructionChip: nodeId });
  },

  recordReconstructionAttempt: (nodeId, correct) => {
    set((s) => {
      // Only record the first attempt — do not overwrite
      if (nodeId in s.reconstructionAccuracy) return s;
      return { reconstructionAccuracy: { ...s.reconstructionAccuracy, [nodeId]: correct } };
    });
  },

  completeReconstruction: () => {
    // startHeatmap() sets discoveryPhase: 'heatmap' — no redundant set() needed
    get().startHeatmap();
    set({ selectedReconstructionChip: null });
  },

  exitCinemaExperience: () => {
    // State-only: set flags that CinemaOverlay's useEffect watches.
    // DOM cleanup (removing heatmap-*, reconstruction-*, discovery-* classes) runs
    // in the component's useEffect cleanup when discoveryActive flips to false.
    set({ discoveryActive: false, discoveryPhase: null, discoveryRoleMap: {} });
  },

  updateNodeCinemaFields: (id, fields) => {
    set((s) => ({
      allNodes: s.allNodes.map((n) => (n.id === id ? { ...n, ...fields } : n)),
      visibleNodes: s.visibleNodes.map((n) => (n.id === id ? { ...n, ...fields } : n)),
      designDirty: true,
    }));
  },

  updateGroupCinemaFields: (id, fields) => {
    set((s) => ({
      groups: s.groups.map((g) => (g.id === id ? { ...g, ...fields } : g)),
      designDirty: true,
    }));
  },

  // ── setEdgePathType ───────────────────────────────────────────────────────
  setEdgePathType: (edgeKey, pathType) => {
    const state = get();
    const undoSnapshot: UndoSnapshot = {
      nodes: [...state.allNodes],
      positions: { ...state.positions },
      groups: [...state.groups],
      edgePathTypes: { ...state.edgePathTypes },
      laneMetrics: { ...state.laneMetrics },
    };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);
    const edgePathTypes = { ...state.edgePathTypes, [edgeKey]: pathType };

    // Re-inject pathTypes into allEdges
    const allEdges = state.allEdges.map((e) => {
      const key = `${e.from}:${e.to}`;
      const pt = edgePathTypes[key];
      return pt ? { ...e, pathType: pt } : e;
    });
    const visibleEdges = state.visibleEdges.map((e) => {
      const key = `${e.from}:${e.to}`;
      const pt = edgePathTypes[key];
      return pt ? { ...e, pathType: pt } : e;
    });

    set({ edgePathTypes, allEdges, visibleEdges, designDirty: true, undoStack, redoStack: [] });
  },

  // ── setEdgePathTypeBatch ──────────────────────────────────────────────────
  setEdgePathTypeBatch: (edgeKeys, pathType) => {
    const state = get();
    const undoSnapshot: UndoSnapshot = {
      nodes: [...state.allNodes],
      positions: { ...state.positions },
      groups: [...state.groups],
      edgePathTypes: { ...state.edgePathTypes },
      laneMetrics: { ...state.laneMetrics },
    };
    const undoStack = [...state.undoStack, undoSnapshot].slice(-50);
    const edgePathTypes = { ...state.edgePathTypes };
    for (const key of edgeKeys) edgePathTypes[key] = pathType;

    const allEdges = state.allEdges.map((e) => {
      const key = `${e.from}:${e.to}`;
      const pt = edgePathTypes[key];
      return pt ? { ...e, pathType: pt } : e;
    });
    const visibleEdges = state.visibleEdges.map((e) => {
      const key = `${e.from}:${e.to}`;
      const pt = edgePathTypes[key];
      return pt ? { ...e, pathType: pt } : e;
    });

    set({ edgePathTypes, allEdges, visibleEdges, designDirty: true, undoStack, redoStack: [] });
  },

  // ── Trace Path state management ───────────────────────────────────────────
  setTracePathSource: (id) => set({ tracePathSource: id, tracePathResults: [], tracePathSelectedIndex: 0 }),

  setTracePathResults: (results, selectedIndex = 0) =>
    set({ tracePathResults: results, tracePathSelectedIndex: selectedIndex }),

  nextTracePath: () =>
    set((s) => ({
      tracePathSelectedIndex: s.tracePathResults.length === 0
        ? 0
        : (s.tracePathSelectedIndex + 1) % s.tracePathResults.length,
    })),

  prevTracePath: () =>
    set((s) => ({
      tracePathSelectedIndex: s.tracePathResults.length === 0
        ? 0
        : (s.tracePathSelectedIndex - 1 + s.tracePathResults.length) % s.tracePathResults.length,
    })),

  clearTracePath: () => set({
    tracePathSource: null,
    tracePathResults: [],
    tracePathSelectedIndex: 0,
    designTool: 'select',
    connectSourceId: null,
  }),

  // ── Critical Path Explorer actions ───────────────────────────────────────
  toggleCriticalPath: () => {
    const s = get();
    if (s.criticalPathActive) {
      if (s.criticalFocusActive) {
        // Restore graph from focus snapshot, then clear all critical state
        const snapshot = s.preCriticalFocusSnapshot;
        if (snapshot) {
          const { visibleNodes, visibleEdges } = deriveVisibility(
            s.allNodes, s.allEdges, s.activeOwners, false, null, s.groups
          );
          set({
            criticalPathActive: false,
            criticalChains: [],
            criticalBottlenecks: [],
            criticalSelectedIds: new Set(),
            criticalCompareMode: false,
            criticalWalkChainId: null,
            criticalWalkCursor: 0,
            criticalFocusActive: false,
            preCriticalFocusSnapshot: null,
            viewMode: snapshot.viewModeAtEnter,
            visibleNodes,
            visibleEdges,
            positions: snapshot.positions,
            laneMetrics: snapshot.laneMetrics,
            flyTarget: snapshot.transform,
          });
          return;
        }
      }
      set({
        criticalPathActive: false,
        criticalChains: [],
        criticalBottlenecks: [],
        criticalSelectedIds: new Set(),
        criticalCompareMode: false,
        criticalWalkChainId: null,
        criticalWalkCursor: 0,
        criticalFocusActive: false,
        preCriticalFocusSnapshot: null,
      });
      return;
    }
    // Exit cinema if active before entering critical path mode
    if (s.discoveryActive) s.exitDiscovery();
    const { chains, bottlenecks } = extractCriticalChains(
      s.allNodes, s.groups, s.allEdges, s.edgePathTypes, s.phases,
    );

    // Fly to fit the first auto-selected chain so the user immediately sees the relevant nodes.
    let flyTarget: Transform | null = null;
    if (chains.length > 0) {
      const canvasEl = document.getElementById('canvas-wrap');
      if (canvasEl) {
        const chainPositions = chains[0].nodeIds
          .map(id => s.positions[id])
          .filter((p): p is Position => p !== undefined);
        if (chainPositions.length > 0) {
          const { width: canvasW, height: canvasH } = canvasEl.getBoundingClientRect();
          const xs = chainPositions.map(p => p.x);
          const ys = chainPositions.map(p => p.y);
          const minX = Math.min(...xs);
          const maxX = Math.max(...xs) + NODE_W;
          const minY = Math.min(...ys);
          const maxY = Math.max(...ys) + NODE_H;
          const graphW = maxX - minX;
          const graphH = maxY - minY;
          const padding = 80;
          const scale = Math.min(
            (canvasW - padding * 2) / graphW,
            (canvasH - padding * 2) / graphH,
            1.5,
          );
          flyTarget = {
            x: (canvasW - graphW * scale) / 2 - minX * scale,
            y: (canvasH - graphH * scale) / 2 - minY * scale,
            k: scale,
          };
        }
      }
    }

    set({
      criticalPathActive: true,
      criticalChains: chains,
      criticalBottlenecks: bottlenecks,
      criticalSelectedIds: chains.length > 0 ? new Set([chains[0].id]) : new Set(),
      criticalCompareMode: false,
      criticalWalkChainId: null,
      criticalWalkCursor: 0,
      ...(flyTarget ? { flyTarget } : {}),
    });
  },

  enterCriticalCompareMode: () => set({ criticalCompareMode: true }),
  exitCriticalCompareMode: () => {
    const s = get();
    const first = [...s.criticalSelectedIds][0];
    set({ criticalCompareMode: false, criticalSelectedIds: first ? new Set([first]) : new Set() });
    // Fit viewport to the remaining selected path.
    if (first) {
      const chain = s.criticalChains.find(c => c.id === first);
      if (chain && chain.nodeIds.length > 0) {
        const canvasEl = document.getElementById('canvas-wrap');
        if (canvasEl) {
          const { width: W, height: H } = canvasEl.getBoundingClientRect();
          const pathPositions = chain.nodeIds.map(id => s.positions[id]).filter(Boolean);
          if (pathPositions.length > 0) {
            const xs = pathPositions.map(p => p.x);
            const ys = pathPositions.map(p => p.y);
            const minX = Math.min(...xs);
            const maxX = Math.max(...xs) + NODE_W;
            const minY = Math.min(...ys);
            const maxY = Math.max(...ys) + NODE_H;
            const graphW = maxX - minX;
            const graphH = maxY - minY;
            const padding = 80;
            const scaleX = (W - padding * 2) / graphW;
            const scaleY = (H - padding * 2) / graphH;
            const k = Math.min(scaleX, scaleY, 1.5);
            const x = (W - graphW * k) / 2 - minX * k;
            const y = (H - graphH * k) / 2 - minY * k;
            set({ flyTarget: { x, y, k } });
          }
        }
      }
    }
  },

  selectAllCriticalPaths: () => {
    const s = get();
    if (s.criticalChains.length === 0) return;
    const allIds = new Set(s.criticalChains.map(c => c.id));
    set({ criticalSelectedIds: allIds, criticalCompareMode: true });
    const canvasEl = document.getElementById('canvas-wrap');
    if (canvasEl) {
      const { width: W, height: H } = canvasEl.getBoundingClientRect();
      const allNodeIds = new Set<string>();
      s.criticalChains.forEach(c => c.nodeIds.forEach(id => allNodeIds.add(id)));
      const pathPositions = [...allNodeIds].map(id => s.positions[id]).filter(Boolean);
      if (pathPositions.length > 0) {
        const xs = pathPositions.map(p => p.x);
        const ys = pathPositions.map(p => p.y);
        const minX = Math.min(...xs);
        const maxX = Math.max(...xs) + NODE_W;
        const minY = Math.min(...ys);
        const maxY = Math.max(...ys) + NODE_H;
        const graphW = maxX - minX;
        const graphH = maxY - minY;
        const padding = 80;
        const scaleX = (W - padding * 2) / graphW;
        const scaleY = (H - padding * 2) / graphH;
        const k = Math.min(scaleX, scaleY, 1.5);
        const x = (W - graphW * k) / 2 - minX * k;
        const y = (H - graphH * k) / 2 - minY * k;
        set({ flyTarget: { x, y, k } });
      }
    }
  },

  setCriticalSelection: (chainId, multi) => {
    const s = get();
    if (!multi) {
      set({ criticalSelectedIds: new Set([chainId]), criticalCompareMode: false });
      // Fly canvas to fit all nodes of the newly selected path.
      const chain = s.criticalChains.find(c => c.id === chainId);
      if (chain && chain.nodeIds.length > 0) {
        const canvasEl = document.getElementById('canvas-wrap');
        if (canvasEl) {
          const { width: W, height: H } = canvasEl.getBoundingClientRect();
          const pathPositions = chain.nodeIds.map(id => s.positions[id]).filter(Boolean);
          if (pathPositions.length > 0) {
            const xs = pathPositions.map(p => p.x);
            const ys = pathPositions.map(p => p.y);
            const minX = Math.min(...xs);
            const maxX = Math.max(...xs) + NODE_W;
            const minY = Math.min(...ys);
            const maxY = Math.max(...ys) + NODE_H;
            const graphW = maxX - minX;
            const graphH = maxY - minY;
            const padding = 80;
            const scaleX = (W - padding * 2) / graphW;
            const scaleY = (H - padding * 2) / graphH;
            const k = Math.min(scaleX, scaleY, 1.5);
            const x = (W - graphW * k) / 2 - minX * k;
            const y = (H - graphH * k) / 2 - minY * k;
            set({ flyTarget: { x, y, k } });
          }
        }
      }
      return;
    }
    const next = new Set(s.criticalSelectedIds);
    if (next.has(chainId)) next.delete(chainId);
    else next.add(chainId);
    set({ criticalSelectedIds: next });
    // Fit viewport to the union of all selected chains.
    if (next.size > 0) {
      const canvasEl = document.getElementById('canvas-wrap');
      if (canvasEl) {
        const { width: W, height: H } = canvasEl.getBoundingClientRect();
        const allNodeIds = new Set<string>();
        for (const cid of next) {
          const chain = s.criticalChains.find(c => c.id === cid);
          if (chain) chain.nodeIds.forEach(id => allNodeIds.add(id));
        }
        const pathPositions = [...allNodeIds].map(id => s.positions[id]).filter(Boolean);
        if (pathPositions.length > 0) {
          const xs = pathPositions.map(p => p.x);
          const ys = pathPositions.map(p => p.y);
          const minX = Math.min(...xs);
          const maxX = Math.max(...xs) + NODE_W;
          const minY = Math.min(...ys);
          const maxY = Math.max(...ys) + NODE_H;
          const graphW = maxX - minX;
          const graphH = maxY - minY;
          const padding = 80;
          const scaleX = (W - padding * 2) / graphW;
          const scaleY = (H - padding * 2) / graphH;
          const k = Math.min(scaleX, scaleY, 1.5);
          const x = (W - graphW * k) / 2 - minX * k;
          const y = (H - graphH * k) / 2 - minY * k;
          set({ flyTarget: { x, y, k } });
        }
      }
    }
  },

  enterCriticalWalk: (chainId) => set({
    criticalWalkChainId: chainId,
    criticalWalkCursor: 0,
    criticalSelectedIds: new Set([chainId]),
    criticalCompareMode: false,
  }),

  stepCriticalWalk: (dir) => {
    const s = get();
    const chain = s.criticalChains.find(c => c.id === s.criticalWalkChainId);
    if (!chain || chain.nodeIds.length === 0) return;
    const len = chain.nodeIds.length;
    const next = ((s.criticalWalkCursor + dir) % len + len) % len;
    set({ criticalWalkCursor: next });
  },

  exitCriticalWalk: () => set({ criticalWalkChainId: null, criticalWalkCursor: 0 }),

  setCriticalWalkCursor: (index) => set({ criticalWalkCursor: index }),

  enterCriticalFocus: (chainId) => {
    const s = get();
    const chain = s.criticalChains.find(c => c.id === chainId);
    if (!chain) return;

    // Cancel any running auto-layout so its result can't overwrite the focus positions.
    if (autoLayoutWorker) {
      autoLayoutWorker.terminate();
      autoLayoutWorker = null;
    }

    // Keep the original snapshot when switching chains while already in focus —
    // so exit always restores to the full graph, not a previous chain's layout.
    const preCriticalFocusSnapshot: FocusSnapshot =
      s.criticalFocusActive && s.preCriticalFocusSnapshot
        ? s.preCriticalFocusSnapshot
        : {
            viewModeAtEnter: s.viewMode,
            positions: { ...s.positions },
            laneMetrics: { ...s.laneMetrics },
            transform: { ...s.transform },
            visibleNodes: [...s.visibleNodes],
            visibleEdges: [...s.visibleEdges],
          };

    const chainNodeIdSet = new Set(chain.nodeIds);
    const focusNodes = s.allNodes.filter(n => chainNodeIdSet.has(n.id));
    const focusEdges = s.allEdges.filter(
      e => chainNodeIdSet.has(e.from) && chainNodeIdSet.has(e.to)
    );

    const { positions, laneMetrics } = derivePositions(
      focusNodes, focusEdges, s.viewMode, s.activeOwners, s.allNodes, s.phases, s.groups
    );

    // Compute the fit transform immediately from the freshly derived positions so
    // the first render already shows the correct zoom — no 60ms delay needed.
    let fitTransform: Transform = s.transform;
    const canvasEl = document.getElementById('canvas-wrap');
    if (canvasEl && Object.keys(positions).length > 0) {
      const { width: canvasW, height: canvasH } = canvasEl.getBoundingClientRect();
      const xs = Object.values(positions).map(p => p.x);
      const ys = Object.values(positions).map(p => p.y);
      const minX = Math.min(...xs);
      const maxX = Math.max(...xs) + NODE_W;
      const minY = Math.min(...ys);
      const maxY = Math.max(...ys) + NODE_H;
      const graphW = maxX - minX;
      const graphH = maxY - minY;
      const padding = 60;
      const scale = Math.min(
        (canvasW - padding * 2) / graphW,
        (canvasH - padding * 2) / graphH,
        1.5,
      );
      fitTransform = {
        x: (canvasW - graphW * scale) / 2 - minX * scale,
        y: (canvasH - graphH * scale) / 2 - minY * scale,
        k: scale,
      };
    }

    set({
      criticalFocusActive: true,
      preCriticalFocusSnapshot,
      criticalSelectedIds: new Set([chainId]),
      criticalCompareMode: false,
      criticalWalkChainId: null,
      criticalWalkCursor: 0,
      visibleNodes: focusNodes,
      visibleEdges: focusEdges,
      positions,
      laneMetrics,
      flyTarget: fitTransform,
      autoLayoutRunning: false,
      autoLayoutPhase: '',
    });
  },

  exitCriticalFocus: () => {
    const s = get();
    const snapshot = s.preCriticalFocusSnapshot;
    if (!snapshot) {
      set({ criticalFocusActive: false });
      get().rebuildGraph();
      setTimeout(() => get().fitToScreen(), 60);
      return;
    }
    // Re-derive from live allNodes (handles group changes made during focus)
    const { visibleNodes, visibleEdges } = deriveVisibility(
      s.allNodes, s.allEdges, s.activeOwners, false, null, s.groups
    );

    // Compute a fit around the currently selected chains at the restored positions
    // so the viewport frames the relevant paths rather than jumping back to the
    // arbitrary pre-focus position.
    let exitFlyTarget: Transform = snapshot.transform;
    const canvasEl = document.getElementById('canvas-wrap');
    if (canvasEl && s.criticalSelectedIds.size > 0) {
      const { width: W, height: H } = canvasEl.getBoundingClientRect();
      const allNodeIds = new Set<string>();
      for (const cid of s.criticalSelectedIds) {
        const chain = s.criticalChains.find(c => c.id === cid);
        if (chain) chain.nodeIds.forEach(id => allNodeIds.add(id));
      }
      const pathPositions = [...allNodeIds]
        .map(id => snapshot.positions[id])
        .filter(Boolean);
      if (pathPositions.length > 0) {
        const xs = pathPositions.map(p => p.x);
        const ys = pathPositions.map(p => p.y);
        const minX = Math.min(...xs);
        const maxX = Math.max(...xs) + NODE_W;
        const minY = Math.min(...ys);
        const maxY = Math.max(...ys) + NODE_H;
        const graphW = maxX - minX;
        const graphH = maxY - minY;
        const padding = 80;
        const k = Math.min((W - padding * 2) / graphW, (H - padding * 2) / graphH, 1.5);
        exitFlyTarget = {
          x: (W - graphW * k) / 2 - minX * k,
          y: (H - graphH * k) / 2 - minY * k,
          k,
        };
      }
    }

    set({
      criticalFocusActive: false,
      preCriticalFocusSnapshot: null,
      // Restore the view mode the user was in before
      viewMode: snapshot.viewModeAtEnter,
      visibleNodes,
      visibleEdges,
      positions: snapshot.positions,
      laneMetrics: snapshot.laneMetrics,
      flyTarget: exitFlyTarget,
    });
  },

  // ── Summon Mode actions ───────────────────────────────────────────────────
  activateSummon: (sourceIds) => {
    if (get().discoveryActive) return;
    const ids = Array.isArray(sourceIds) ? sourceIds : [sourceIds];
    set({
      summonActive: true,
      summonSourceId: ids[0] ?? null,
      summonSourceIds: ids,
      summonFilter: '',
      summonShowRing: false,
      summonPingTarget: null,
      summonConnected: new Set(),
    });
  },

  deactivateSummon: () => {
    set({
      summonActive: false,
      summonSourceId: null,
      summonSourceIds: [],
      summonFilter: '',
      summonShowRing: false,
      summonPingTarget: null,
      summonConnected: new Set(),
    });
  },

  setSummonFilter: (q) => set({ summonFilter: q, summonShowRing: false }),

  toggleSummonRing: () => set((s) => ({ summonShowRing: !s.summonShowRing })),

  setSummonPingTarget: (t) => set({ summonPingTarget: t }),

  addSummonConnected: (nodeId) => {
    set((s) => {
      const next = new Set(s.summonConnected);
      next.add(nodeId);
      return { summonConnected: next };
    });
  },

  // ── runAutoLayout ─────────────────────────────────────────────────────────
  runAutoLayout: (selectedNodeIds) => {
    const state = get();

    // Cancel any in-progress run before starting a new one
    if (autoLayoutWorker) {
      autoLayoutWorker.terminate();
      autoLayoutWorker = null;
    }

    set({
      autoLayoutRunning: true,
      autoLayoutPhase: '',
      autoLayoutFromPositions: { ...state.positions },
    });

    const worker = new Worker(
      new URL('../workers/autoLayout.worker.ts', import.meta.url),
      { type: 'module' }
    );
    autoLayoutWorker = worker;

    const msg = {
      nodes: state.visibleNodes,
      edges: state.visibleEdges,
      groups: state.groups,
      phases: state.phases.length > 0 ? state.phases : undefined,
      mode: state.viewMode,
      selectedOnly: selectedNodeIds && selectedNodeIds.length > 0
        ? new Set(selectedNodeIds)
        : undefined,
    };

    worker.onmessage = (event) => {
      const data = event.data as { type: string; phase?: string; positions?: Record<string, { x: number; y: number }>; message?: string };
      if (data.type === 'progress') {
        set({ autoLayoutPhase: data.phase ?? '' });
      } else if (data.type === 'done' && data.positions) {
        const currentState = get();
        const newPositions = { ...currentState.positions, ...data.positions };
        set({ positions: newPositions, autoLayoutRunning: false, autoLayoutPhase: '' });
        // Don't corrupt the layout cache with focus-only positions
        if (!get().criticalFocusActive) get().saveLayoutToCache();
        autoLayoutWorker = null;
        setTimeout(() => get().fitToScreen(true), 50);
      } else if (data.type === 'error') {
        console.error('Auto-layout error:', data.message);
        set({ autoLayoutRunning: false, autoLayoutPhase: '', autoLayoutFromPositions: null });
        autoLayoutWorker = null;
      }
    };

    worker.onerror = (err) => {
      console.error('Auto-layout worker error:', err);
      set({ autoLayoutRunning: false, autoLayoutPhase: '', autoLayoutFromPositions: null });
      autoLayoutWorker = null;
    };

    worker.postMessage(msg);
  },

  // ── clearAutoLayoutFromPositions ──────────────────────────────────────────
  clearAutoLayoutFromPositions: () => set({ autoLayoutFromPositions: null }),
}));
